import { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

interface OnlineParticlesProps {
  isAnniversary?: boolean;
  bothOnline?: boolean;
}

function ParticleField({ isAnniversary, bothOnline }: OnlineParticlesProps) {
  const pointsRef = useRef<THREE.Points>(null);
  
  const particleCount = isAnniversary ? 300 : (bothOnline ? 100 : 0);
  
  const [positions, speeds, phases] = useMemo(() => {
    const pos = new Float32Array(300 * 3);
    const spd = new Float32Array(300);
    const phs = new Float32Array(300);
    
    for (let i = 0; i < 300; i++) {
      // x: -5 to 5, y: -5 to 5, z: -2 to 2
      pos[i * 3] = (Math.random() - 0.5) * 10;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 10;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 4;
      
      spd[i] = 0.2 + Math.random() * 0.5;
      phs[i] = Math.random() * Math.PI * 2;
    }
    return [pos, spd, phs];
  }, []);

  useFrame((state, delta) => {
    if (!pointsRef.current || particleCount === 0) return;
    
    const positions = pointsRef.current.geometry.attributes.position.array as Float32Array;
    
    for (let i = 0; i < particleCount; i++) {
      // Move up
      positions[i * 3 + 1] += speeds[i] * delta * (isAnniversary ? 1.5 : 0.5);
      
      // Gentle sway
      positions[i * 3] += Math.sin(state.clock.elapsedTime + phases[i]) * delta * 0.2;
      
      // Reset if too high
      if (positions[i * 3 + 1] > 5) {
        positions[i * 3 + 1] = -5;
      }
    }
    
    pointsRef.current.geometry.attributes.position.needsUpdate = true;
  });

  if (particleCount === 0) return null;

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={particleCount}
          array={positions}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        size={isAnniversary ? 0.08 : 0.05}
        color="#B8955A"
        transparent
        opacity={isAnniversary ? 0.8 : 0.4}
        blending={THREE.AdditiveBlending}
        depthWrite={false}
      />
    </points>
  );
}

export default function OnlineParticles({ isAnniversary = false, bothOnline = true }: OnlineParticlesProps) {
  if (!isAnniversary && !bothOnline) return null;

  return (
    <div className="absolute inset-0 z-0 pointer-events-none">
      <Canvas camera={{ position: [0, 0, 5], fov: 45 }}>
        <ParticleField isAnniversary={isAnniversary} bothOnline={bothOnline} />
      </Canvas>
    </div>
  );
}

import { useEffect, useState } from "react";
import { motion } from "motion/react";

export default function AnniversaryParticles() {
  const [particles, setParticles] = useState<{ id: number; x: number; delay: number; duration: number }[]>([]);

  useEffect(() => {
    const newParticles = Array.from({ length: 20 }).map((_, i) => ({
      id: i,
      x: Math.random() * 100,
      delay: Math.random() * 5,
      duration: 10 + Math.random() * 10
    }));
    setParticles(newParticles);
  }, []);

  return (
    <div className="pointer-events-none fixed inset-0 z-0 overflow-hidden">
      {particles.map(p => (
        <motion.div
          key={p.id}
          initial={{ opacity: 0, y: "100vh", x: `${p.x}vw` }}
          animate={{ opacity: [0, 0.6, 0], y: "-10vh" }}
          transition={{
            duration: p.duration,
            delay: p.delay,
            repeat: Infinity,
            ease: "linear"
          }}
          className="absolute h-2 w-2 rounded-full bg-brass blur-[1px]"
        />
      ))}
    </div>
  );
}

import { createContext, useContext, useEffect, useState } from "react";
import { auth, db } from "../firebase";
import { signInWithPopup, onAuthStateChanged, User, GoogleAuthProvider } from "firebase/auth";
import { doc, getDoc, updateDoc, deleteDoc, setDoc, onSnapshot } from "firebase/firestore";
import { motion } from "framer-motion";

enum OperationType {
  CREATE = 'create',
  UPDATE = 'update',
  DELETE = 'delete',
  LIST = 'list',
  GET = 'get',
  WRITE = 'write',
}

interface FirestoreErrorInfo {
  error: string;
  operationType: OperationType;
  path: string | null;
  authInfo: {
    userId: string | undefined;
    email: string | null | undefined;
    emailVerified: boolean | undefined;
    isAnonymous: boolean | undefined;
    tenantId: string | null | undefined;
    providerInfo: {
      providerId: string;
      displayName: string | null;
      email: string | null;
      photoUrl: string | null;
    }[];
  }
}

function handleFirestoreError(error: unknown, operationType: OperationType, path: string | null) {
  const errInfo: FirestoreErrorInfo = {
    error: error instanceof Error ? error.message : String(error),
    authInfo: {
      userId: auth.currentUser?.uid,
      email: auth.currentUser?.email,
      emailVerified: auth.currentUser?.emailVerified,
      isAnonymous: auth.currentUser?.isAnonymous,
      tenantId: auth.currentUser?.tenantId,
      providerInfo: auth.currentUser?.providerData.map(provider => ({
        providerId: provider.providerId,
        displayName: provider.displayName,
        email: provider.email,
        photoUrl: provider.photoURL
      })) || []
    },
    operationType,
    path
  }
  console.error('Firestore Error: ', JSON.stringify(errInfo));
  throw new Error(JSON.stringify(errInfo));
}

interface AuthState {
  user: User | null;
  loading: boolean;
  hasHousehold: boolean;
  householdId: string | null;
  error: string;
  userData?: any;
  googleAccessToken: string | null;
}

interface AuthContextType extends AuthState {
  signIn: () => Promise<void>;
  connectGoogleCalendar: () => Promise<boolean>;
  clearGoogleToken: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within an AuthProvider");
  return context;
}

export default function AuthWrapper({ children }: { children: React.ReactNode }) {
  const [authState, setAuthState] = useState<AuthState>({
    user: null,
    loading: true,
    hasHousehold: false,
    householdId: null,
    error: "",
    googleAccessToken: null,
  });

  const connectGoogleCalendar = async () => {
    if (!authState.user) return false;
    
    const provider = new GoogleAuthProvider();
    provider.addScope('https://www.googleapis.com/auth/calendar.events');
    provider.addScope('https://www.googleapis.com/auth/calendar.readonly');
    
    // Request offline access to get a refresh token
    provider.setCustomParameters({
      access_type: 'offline',
      prompt: 'consent'
    });
    
    try {
      const result = await signInWithPopup(auth, provider);
      
      // The credential only contains the short-lived accessToken
      const credential = GoogleAuthProvider.credentialFromResult(result);
      const accessToken = credential?.accessToken;
      
      // The refreshToken is found in the _tokenResponse for signInWithPopup
      // when access_type=offline and prompt=consent are used
      const tokenResponse = (result as any)._tokenResponse;
      const refreshToken = tokenResponse?.refreshToken;
      
      if (accessToken) {
        const tokenData: any = {
          accessToken,
          expiresAt: Date.now() + 3500 * 1000, // 3500 to be safe (Google is 3600)
          updatedAt: new Date().toISOString()
        };

        // ONLY update refreshToken if it's present (usually only on first consent)
        if (refreshToken) {
          tokenData.refreshToken = refreshToken;
        }

        // Store in Firestore
        await setDoc(doc(db, "users", authState.user.uid, "googleCalendarToken", "current"), tokenData, { merge: true });
        
        // Update user document
        await updateDoc(doc(db, "users", authState.user.uid), {
          calendarConnected: true,
          calendarEmail: result.user.email,
          updatedAt: new Date().toISOString()
        });
        
        setAuthState(prev => ({
          ...prev,
          googleAccessToken: accessToken,
          userData: { ...prev.userData, calendarConnected: true, calendarEmail: result.user.email }
        }));
        
        return true;
      }
    } catch (error) {
      console.error("Error connecting Google Calendar:", error);
      return false;
    }
    return false;
  };

  const clearGoogleToken = async () => {
    if (authState.user) {
      try {
        await deleteDoc(doc(db, "users", authState.user.uid, "googleCalendarToken", "current"));
        await updateDoc(doc(db, "users", authState.user.uid), {
          calendarConnected: false
        });
      } catch (err) {
        console.error("Error clearing token:", err);
      }
    }
    setAuthState(prev => ({ ...prev, googleAccessToken: null }));
  };

  useEffect(() => {
    let userDocUnsubscribe: (() => void) | null = null;

    const authUnsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      if (currentUser) {
        // First, set the user so we can show the loading state for the doc
        setAuthState(prev => ({ ...prev, user: currentUser, loading: true }));

        // Listen to the user document in real-time
        const userDocRef = doc(db, "users", currentUser.uid);
        
        if (userDocUnsubscribe) userDocUnsubscribe();
        
        userDocUnsubscribe = onSnapshot(userDocRef, async (snapshot) => {
          if (snapshot.exists()) {
            const userData = snapshot.data();
            const householdId = userData?.householdId || null;
            const hasHousehold = !!householdId;

            // Fetch token from Firestore (one-time fetch is fine here, or we could listen too)
            const tokenDoc = await getDoc(doc(db, "users", currentUser.uid, "googleCalendarToken", "current"));
            const googleAccessToken = tokenDoc.exists() ? tokenDoc.data().accessToken : null;

            setAuthState(prev => ({
              ...prev,
              loading: false,
              hasHousehold,
              householdId,
              userData,
              googleAccessToken,
              error: "",
            }));
          } else {
            // Create user doc if it doesn't exist
            const newUser = {
              uid: currentUser.uid,
              email: currentUser.email,
              displayName: currentUser.displayName,
              photoURL: currentUser.photoURL,
              createdAt: new Date().toISOString(),
              updatedAt: new Date().toISOString()
            };
            await setDoc(userDocRef, newUser);
            
            setAuthState(prev => ({
              ...prev,
              loading: false,
              hasHousehold: false,
              householdId: null,
              userData: newUser,
              googleAccessToken: null,
              error: "",
            }));
          }
        }, (err: any) => {
          console.error("Error listening to user doc:", err);
          setAuthState(prev => ({ ...prev, loading: false, error: "Failed to load user data" }));
        });
      } else {
        if (userDocUnsubscribe) {
          userDocUnsubscribe();
          userDocUnsubscribe = null;
        }
        setAuthState(prev => ({
          ...prev,
          user: null,
          loading: false,
          hasHousehold: false,
          householdId: null,
          userData: null,
          googleAccessToken: null,
          error: "",
        }));
      }
    });

    return () => {
      authUnsubscribe();
      if (userDocUnsubscribe) userDocUnsubscribe();
    };
  }, []);

  const handleGoogleSignIn = async () => {
    try {
      setAuthState(prev => ({ ...prev, error: "" }));
      const provider = new GoogleAuthProvider();
      await signInWithPopup(auth, provider);
    } catch (err: any) {
      setAuthState(prev => ({ ...prev, error: err.message || "Failed to sign in" }));
    }
  };

  if (authState.loading) {
    return (
