          />

          <motion.p
            initial={{ opacity: 0, y: 40, filter: "blur(4px)" }}
            animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
            transition={{ ...springConfig, delay: 0.16 }}
            style={{
              fontFamily: "'Outfit', sans-serif",
              fontSize: "16px",
