            }}
          >
            <svg width="18" height="18" viewBox="0 0 24 24">
              <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
              <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
              <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
              <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
            </svg>
            Continue with Google
          </motion.button>

          <motion.p
            initial={{ opacity: 0, y: 40, filter: "blur(4px)" }}
            animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
            transition={{ ...springConfig, delay: 0.32 }}
            style={{
              fontFamily: "'Outfit', sans-serif",
              fontSize: "12px",
              color: "#D4CEC4",
              textAlign: "center",
              marginTop: "16px"
            }}
          >
            Private & secure — just for two
          </motion.p>

          {authState.error && (
            <motion.p 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="mt-4 text-sm text-red-500"
            >
              {authState.error}
            </motion.p>
          )}
        </div>
      </div>
    );
  }

  return (
    <AuthContext.Provider value={{ ...authState, signIn: handleGoogleSignIn, connectGoogleCalendar, clearGoogleToken }}>
      {children}
    </AuthContext.Provider>
  );
}

import { useState, useEffect, useMemo } from "react";
import { motion, AnimatePresence } from "motion/react";
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where, 
  orderBy, 
  limit, 
  Timestamp,
  getDoc,
  updateDoc,
  getDocs
} from "firebase/firestore";
import { db } from "../../firebase";
import { useAuth } from "../AuthWrapper";
import { format, isSameMonth, isSameDay, differenceInYears, isSunday } from "date-fns";
import { getOrUpdateInsights, Insight } from "../../services/relationshipIntelligence";
import { startProactiveBrain, ProactiveAlert } from "../../services/proactiveBrain";
import { X, Heart, Gift, Sparkles, RefreshCw, RefreshCcw, ChevronRight, Calendar, DollarSign, ShoppingCart } from "lucide-react";
import { saveMood, MOOD_EMOJIS, MoodEntry } from "../../services/moodService";
import { getSpecialDates, SpecialDate, checkReminders, getEarliestMemory } from "../../services/specialDatesService";
import { generateWeeklySummary, dismissWeeklySummary, WeeklySummary } from "../../services/weeklySummaryService";
import confetti from "canvas-confetti";
import BottomSheet from "../ui/BottomSheet";
import { GoogleGenerativeAI } from "@google/generative-ai";

// --- Types ---
enum OperationType {
  CREATE = 'create',
  UPDATE = 'update',
  DELETE = 'delete',
  LIST = 'list',
  GET = 'get',
  WRITE = 'write',
}

interface FirestoreErrorInfo {
  error: string;
  operationType: OperationType;
  path: string | null;
  authInfo: {
    userId: string | undefined;
    email: string | null | undefined;
    emailVerified: boolean | undefined;
    isAnonymous: boolean | undefined;
    tenantId: string | null | undefined;
    providerInfo: {
      providerId: string;
      displayName: string | null;
      email: string | null;
      photoUrl: string | null;
    }[];
  }
}

interface PartnerData {
  displayName: string;
  photoURL: string;
  isOnline: boolean;
  lastSeen: Timestamp;
}

interface EventData {
  title: string;
  date: Timestamp;
}

interface MemoryData {
  imageUrl: string;
  caption: string;
  createdAt: Timestamp;
}

interface NoteData {
  text: string;
  authorName: string;
  createdAt: Timestamp;
}

// --- Animation Constants ---
const spring = { type: "spring" as const, stiffness: 280, damping: 22 };

const fadeUp = (delay = 0) => ({
  initial: { opacity: 0, y: 40, filter: "blur(4px)" },
  animate: { opacity: 1, y: 0, filter: "blur(0px)" },
  transition: { ...spring, delay }
});

const cardHover = {
  y: -6,
  boxShadow: "0 12px 32px rgba(26,26,26,0.12)",
  transition: { type: "spring" as const, stiffness: 300, damping: 20 }
};

const cardTap = { scale: 0.98 };

// --- Helper Components ---
const ensureDate = (val: any): Date | null => {
  if (!val) return null;
  if (val instanceof Date) return val;
  if (typeof val.toDate === 'function') return val.toDate();
  if (typeof val === 'object' && val.seconds !== undefined) return new Date(val.seconds * 1000);
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
};

const Section = ({ children, delay = 0, className = "", id }: { children: React.ReactNode, delay?: number, className?: string, id?: string }) => (
  <motion.section 
    layout
    {...fadeUp(delay)}
    id={id}
    className={`w-full px-5 ${className}`}
  >
    {children}
  </motion.section>
);

const Card = ({ children, onClick, className = "", layoutId }: { children: React.ReactNode, onClick?: () => void, className?: string, layoutId?: string }) => (
  <motion.div
    layoutId={layoutId}
    whileHover={onClick ? { ...cardHover, backgroundColor: "rgba(255, 255, 255, 0.6)" } : undefined}
    whileTap={onClick ? cardTap : undefined}
    onClick={onClick}
    className={`glass-card border border-stone/30 rounded-[28px] overflow-hidden ${onClick ? 'cursor-pointer' : ''} ${className}`}
    style={{
      background: "var(--glass-bg)",
      backdropFilter: "var(--glass-blur)",
      boxShadow: "var(--glass-shadow)"
    }}
  >
    {children}
  </motion.div>
);

const LivePulse = ({ active }: { active: boolean }) => (
  <div className="flex items-center gap-2 px-3 py-1 bg-white/40 backdrop-blur-md rounded-full border border-white/50 shadow-sm">
    <div className="relative w-2 h-2">
      <div className={`absolute inset-0 rounded-full bg-green-500 ${active ? 'animate-[pulse-live_2s_infinite]' : ''}`} />
      <div className="absolute inset-0 rounded-full bg-green-500/40 blur-[2px]" />
    </div>
    <span className="font-outfit text-[10px] uppercase tracking-widest font-bold text-charcoal/60">
      {active ? "Live Syncing" : "Connected"}
    </span>
  </div>
);

const EmptyState = ({ text }: { text: string }) => (
  <p className="font-outfit italic text-stone text-sm">{text}</p>
);

// --- Main Component ---
interface DashboardHomeProps {
  onNavigate: (tab: string) => void;
}

export default function DashboardHome({ onNavigate }: DashboardHomeProps) {
  const { user } = useAuth();
  const [userData, setUserData] = useState<any>(null);
  const [partnerData, setPartnerData] = useState<PartnerData | null>(null);
  const [nextEvent, setNextEvent] = useState<EventData | null>(null);
  const [groceryCount, setGroceryCount] = useState(0);
  const [monthlySpend, setMonthlySpend] = useState(0);
  const [lastMemory, setLastMemory] = useState<MemoryData | null>(null);
  const [lastNote, setLastNote] = useState<NoteData | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [insights, setInsights] = useState<Insight[] | null>(null);
  const [alerts, setAlerts] = useState<ProactiveAlert[]>([]);
  const [myMood, setMyMood] = useState<MoodEntry | null>(null);
  const [partnerMood, setPartnerMood] = useState<MoodEntry | null>(null);
  const [specialDates, setSpecialDates] = useState<SpecialDate[]>([]);
  const [isAnniversary, setIsAnniversary] = useState(false);
  const [isPartnerBirthday, setIsPartnerBirthday] = useState(false);
  const [earliestMemory, setEarliestMemory] = useState<any>(null);
  const [weeklySummary, setWeeklySummary] = useState<WeeklySummary | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [selectedDateForGifts, setSelectedDateForGifts] = useState<SpecialDate | null>(null);
  const [giftSuggestions, setGiftSuggestions] = useState<any[]>([]);
  const [loadingGifts, setLoadingGifts] = useState(false);
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [startY, setStartY] = useState(0);
  const [pullOffset, setPullOffset] = useState(0);

  // --- Error Handler ---
  const handleError = (error: any, op: OperationType, path: string) => {
    const errInfo: FirestoreErrorInfo = {
      error: error.message,
      operationType: op,
      path,
      authInfo: {
        userId: user?.uid,
        email: user?.email,
        emailVerified: user?.emailVerified,
        isAnonymous: user?.isAnonymous,
        tenantId: user?.tenantId,
        providerInfo: user?.providerData.map(p => ({
          providerId: p.providerId,
          displayName: p.displayName,
          email: p.email,
          photoUrl: p.photoURL
        })) || []
      }
    };
    console.error('Firestore Error:', JSON.stringify(errInfo));
  };

  // --- Time-aware Logic ---
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const sydneyTime = useMemo(() => {
    return new Intl.DateTimeFormat("en-AU", {
      timeZone: "Australia/Sydney",
      hour: "numeric",
      hour12: false
    }).format(currentTime);
  }, [currentTime]);

  const hour = parseInt(sydneyTime);
  
  const timeConfig = useMemo(() => {
    if (isAnniversary) return { bg: "linear-gradient(to bottom, #F5EDD8, #F8F4EE)", greeting: "Happy Anniversary! 🎉", dark: false };
    if (isPartnerBirthday) return { bg: "#F8F4EE", greeting: `It's ${partnerData?.displayName || 'Partner'}'s birthday today! 🎂`, dark: false };
    
    if (hour >= 5 && hour < 10) return { bg: "#E8EEF4", greeting: "Good Morning", dark: false };
    if (hour >= 10 && hour < 15) return { bg: "#F8F4EE", greeting: "Good Afternoon", dark: false };
    if (hour >= 15 && hour < 19) return { bg: "#F5EDD8", greeting: "Golden Hour", dark: false };
    return { bg: "#1A1A1A", greeting: "Good Evening", dark: true };
  }, [hour]);

  // --- Data Fetching ---
  useEffect(() => {
    if (!user) return;

    // 1. User Data
    const userPath = `users/${user.uid}`;
    const unsubUser = onSnapshot(doc(db, "users", user.uid), 
      (snapshot) => {
        setIsSyncing(true);
        setUserData(snapshot.data());
        setTimeout(() => setIsSyncing(false), 800);
      },
      (err) => handleError(err, OperationType.GET, userPath)
    );

    // 2. Partner Data
    let unsubPartner: (() => void) | null = null;
    let unsubHousehold: (() => void) | null = null;
    let unsubEvent: (() => void) | null = null;
    let unsubGroceries: (() => void) | null = null;
    let unsubExpenses: (() => void) | null = null;
    let unsubMemory: (() => void) | null = null;
    let unsubNote: (() => void) | null = null;

    if (userData?.householdId) {
      const householdPath = `households/${userData.householdId}`;
      
      // Fetch Special Dates
      const fetchSpecial = async () => {
        const hSnap = await getDoc(doc(db, "households", userData.householdId));
        const hData = hSnap.data();
        const partnerId = hData?.memberIds?.find((id: string) => id !== user.uid);
        
        const dates = await getSpecialDates(userData.householdId, user.uid, partnerId || null);
        setSpecialDates(dates);
        checkReminders(userData.householdId, dates);

        // Check for Anniversary
        const annivDate = dates.find(d => d.type === 'anniversary');
        if (annivDate && annivDate.daysUntil === 0) {
          setIsAnniversary(true);
          const memory = await getEarliestMemory(userData.householdId);
          setEarliestMemory(memory);
          
          // Trigger Confetti
          confetti({
            colors: ["#B8955A", "#F0E4CC", "#C47B6A", "#E8A090"],
            particleCount: 120,
            spread: 100,
            origin: { y: 0.6 }
          });
        }

        // Check for Partner Birthday
        const partnerBday = dates.find(d => d.type === 'birthday' && d.name.includes("'s Birthday"));
        if (partnerBday && partnerBday.daysUntil === 0) {
          setIsPartnerBirthday(true);
        }
      };
      fetchSpecial();

      unsubHousehold = onSnapshot(doc(db, "households", userData.householdId), 
        (snapshot) => {
          const hData = snapshot.data();
          const partnerId = hData?.memberIds?.find((id: string) => id !== user.uid);
          
          if (partnerId) {
            const partnerPath = `users/${partnerId}`;
            if (unsubPartner) unsubPartner();
            unsubPartner = onSnapshot(doc(db, "users", partnerId), 
              (pSnap) => {
                setIsSyncing(true);
                setPartnerData(pSnap.data() as PartnerData);
                setTimeout(() => setIsSyncing(false), 800);
              },
              (err) => handleError(err, OperationType.GET, partnerPath)
            );
          } else {
            if (unsubPartner) unsubPartner();
            unsubPartner = null;
            setPartnerData(null);
          }
        },
        (err) => handleError(err, OperationType.GET, householdPath)
      );
      
      // 3. Next Event
      const eventsPath = `${householdPath}/events`;
      unsubEvent = onSnapshot(
        query(
          collection(db, "households", userData.householdId, "events"),
          where("date", ">=", Timestamp.now()),
          orderBy("date", "asc"),
          limit(1)
        ),
        (snap) => {
          setIsSyncing(true);
          setNextEvent(snap.docs[0]?.data() as EventData);
          setTimeout(() => setIsSyncing(false), 800);
        },
        (err) => handleError(err, OperationType.LIST, eventsPath)
      );

      // 4. Grocery Count
      const groceriesPath = `${householdPath}/groceries`;
      unsubGroceries = onSnapshot(
        query(
          collection(db, "households", userData.householdId, "groceries"),
          where("completed", "==", false)
        ),
        (snap) => {
          setIsSyncing(true);
          setGroceryCount(snap.size);
          setTimeout(() => setIsSyncing(false), 800);
        },
        (err) => handleError(err, OperationType.LIST, groceriesPath)
      );

      // 5. Monthly Spend
      const expensesPath = `${householdPath}/expenses`;
      unsubExpenses = onSnapshot(
        collection(db, "households", userData.householdId, "expenses"),
        (snap) => {
          const total = snap.docs
            .map(d => d.data())
            .filter(d => {
              const date = ensureDate(d.date);
              return date && isSameMonth(date, new Date());
            })
            .reduce((acc, curr) => acc + (curr.amount || curr.total || 0), 0);
          setIsSyncing(true);
          setMonthlySpend(total);
          setTimeout(() => setIsSyncing(false), 800);
        },
        (err) => handleError(err, OperationType.LIST, expensesPath)
      );

      // 6. Last Memory
      const memoriesPath = `${householdPath}/memories`;
      unsubMemory = onSnapshot(
        query(
          collection(db, "households", userData.householdId, "memories"),
          orderBy("createdAt", "desc"),
          limit(1)
        ),
        (snap) => {
          setIsSyncing(true);
          setLastMemory(snap.docs[0]?.data() as MemoryData);
          setTimeout(() => setIsSyncing(false), 800);
        },
        (err) => handleError(err, OperationType.LIST, memoriesPath)
      );

      // 7. Last Note
      const notesPath = `${householdPath}/notes`;
      unsubNote = onSnapshot(
        query(
          collection(db, "households", userData.householdId, "notes"),
          orderBy("createdAt", "desc"),
          limit(1)
        ),
        (snap) => {
          setIsSyncing(true);
          setLastNote(snap.docs[0]?.data() as NoteData);
          setTimeout(() => setIsSyncing(false), 800);
        },
        (err) => handleError(err, OperationType.LIST, notesPath)
      );

      // 8. Moods
      const today = new Date().toISOString().split('T')[0];
      const moodsRef = collection(db, "households", userData.householdId, "moods");
      const unsubMoods = onSnapshot(
        query(moodsRef, where("date", "==", today)),
        (snap) => {
          const todayMoods = snap.docs.map(d => d.data() as MoodEntry);
          setMyMood(todayMoods.find(m => m.userId === user.uid) || null);
          
          const hData = userData; // We already have householdId from userData
          const partnerId = hData?.memberIds?.find((id: string) => id !== user.uid);
          if (partnerId) {
            setPartnerMood(todayMoods.find(m => m.userId === partnerId) || null);
          }
        }
      );
    }

    return () => {
      unsubUser();
      if (unsubHousehold) unsubHousehold();
      if (unsubPartner) unsubPartner();
      if (unsubEvent) unsubEvent();
      if (unsubGroceries) unsubGroceries();
      if (unsubExpenses) unsubExpenses();
      if (unsubMemory) unsubMemory();
      if (unsubNote) unsubNote();
    };
  }, [user, userData?.householdId]);

  // --- Proactive Brain ---
  useEffect(() => {
    if (!userData?.householdId || !user) return;

    let stopBrain: (() => void) | null = null;
    let unsubAlerts: (() => void) | null = null;

    const initBrain = async () => {
      const hSnap = await getDoc(doc(db, "households", userData.householdId));
      const hData = hSnap.data();
      const pId = hData?.memberIds?.find((id: string) => id !== user.uid);
      
      if (pId) {
        stopBrain = startProactiveBrain(userData.householdId, user.uid, pId);
        
        // Listen for unread alerts
        const alertsRef = collection(db, 'households', userData.householdId, 'proactiveAlerts');
        const q = query(
          alertsRef, 
          where('read', '==', false), 
          orderBy('detectedAt', 'desc'),
          limit(3)
        );
        
        unsubAlerts = onSnapshot(q, (snap) => {
          setAlerts(snap.docs.map(d => ({ id: d.id, ...d.data() } as ProactiveAlert)));
        });
      }
    };

    initBrain();

    return () => {
      if (stopBrain) stopBrain();
      if (unsubAlerts) unsubAlerts();
    };
  }, [userData?.householdId, user?.uid]);

  // --- Insights Logic ---
  const fetchInsights = async (force = false) => {
    if (!userData?.householdId || !user) return;
    
    setLoadingInsights(true);
    try {
      const hSnap = await getDoc(doc(db, "households", userData.householdId));
      const hData = hSnap.data();
      const partnerId = hData?.memberIds?.find((id: string) => id !== user.uid);
      
      if (!partnerId) {
        setLoadingInsights(false);
        return;
      }

      const pSnap = await getDoc(doc(db, "users", partnerId));
      const pData = pSnap.data();

      const result = await getOrUpdateInsights(
        userData.householdId,
        user.uid,
        partnerId,
        userData.displayName || "You",
        pData?.displayName || "Partner",
        force
      );
      setInsights(result);
    } catch (err) {
      console.error("Error fetching insights:", err);
    } finally {
      setLoadingInsights(false);
    }
  };

  const fetchGiftSuggestions = async (date: SpecialDate) => {
    if (!userData?.householdId) return;
    setLoadingGifts(true);
    setSelectedDateForGifts(date);
    const apiKey = import.meta.env.VITE_GEMINI_API_KEY;
    if (!apiKey) return;

    const genAI = new GoogleGenerativeAI(apiKey);
    const model = genAI.getGenerativeModel({ model: "gemini-flash-latest" });
    
    // Get context
    const savingsSnap = await getDocs(collection(db, "households", userData.householdId, "savingsGoals"));
    const totalSavings = savingsSnap.docs.reduce((acc, d) => acc + (d.data().currentAmount || 0), 0);
    
    const bucketSnap = await getDocs(collection(db, "households", userData.householdId, "bucketList"));
    const interests = bucketSnap.docs.map(d => d.data().title).join(", ");

    const prompt = `Suggest 4 thoughtful gift ideas for a ${date.name} in ${date.daysUntil} days.
    Current savings available: $${totalSavings}
    Monthly budget remaining: $${(2000 - monthlySpend).toFixed(2)} (estimated)
    Their shared interests based on bucket list: ${interests || "travel, cooking, home improvement"}
    Return ONLY JSON array (no markdown):
    [{ "emoji": "string", "name": "string", "description": "max 15 words", "estimatedCost": "string", "link": null }]`;

    try {
      const result = await model.generateContent(prompt);
      const text = result.response.text().trim().replace(/```json\n?/g, '').replace(/```\n?/g, '');
      setGiftSuggestions(JSON.parse(text || "[]"));
    } catch (err) {
      console.error("Gift suggestions failed:", err);
    } finally {
      setLoadingGifts(false);
    }
  };

  const fetchWeeklySummary = async () => {
    if (!userData?.householdId || !user) return;
    
    setLoadingSummary(true);
    try {
      // Get partner ID from household
      const hSnap = await getDoc(doc(db, "households", userData.householdId));
      const hData = hSnap.data();
      const partnerId = hData?.memberIds?.find((id: string) => id !== user.uid);

      if (!partnerId) {
        setLoadingSummary(false);
        return;
      }

      const summary = await generateWeeklySummary(
        userData.householdId,
        user.uid,
        userData.displayName || "You",
        partnerId,
        partnerData?.displayName || "Partner"
      );
      
      if (summary) {
        if (summary.dismissedAt && summary.generatedAt) {
          const dismissedDate = summary.dismissedAt.toDate();
          const generatedDate = summary.generatedAt.toDate();
          if (dismissedDate >= generatedDate) {
            setWeeklySummary(null);
          } else {
            setWeeklySummary(summary);
          }
        } else {
          setWeeklySummary(summary);
        }
      }
    } catch (error) {
      console.error("Error fetching weekly summary:", error);
    } finally {
      setLoadingSummary(false);
    }
  };

  const handleDismissSummary = async () => {
    if (userData?.householdId) {
      await dismissWeeklySummary(userData.householdId);
      setWeeklySummary(null);
    }
  };

  useEffect(() => {
    if (userData?.householdId) {
      fetchInsights();
      fetchWeeklySummary();
      // Auto refresh every 24 hours
      const interval = setInterval(() => {
        fetchInsights();
        fetchWeeklySummary();
      }, 24 * 60 * 60 * 1000);
      return () => clearInterval(interval);
    }
  }, [userData?.householdId, partnerData, user]);

  // --- Pull to Refresh Logic ---
  const REFRESH_THRESHOLD = 80;

  const handleTouchStart = (e: React.TouchEvent) => {
    const container = e.currentTarget as HTMLDivElement;
    if (container.scrollTop <= 0) {
      setStartY(e.touches[0].pageY);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (startY === 0) return;
    const y = e.touches[0].pageY;
    const dist = y - startY;
    
    if (dist > 0) {
      // Dampened elastic effect: logarithmic-ish scaling
      const dampenedDist = Math.pow(dist, 0.85) * 2;
      setPullOffset(dampenedDist);
      
      // Prevent default scrolling when pulling
      if (dist > 10 && e.cancelable) {
        e.preventDefault();
      }
    }
  };

  const handleTouchEnd = () => {
    if (pullOffset > REFRESH_THRESHOLD && !isRefreshing) {
      setIsRefreshing(true);
      fetchInsights(true).then(() => {
        setIsRefreshing(false);
        setPullOffset(0);
        setStartY(0);
      });
    } else {
      setPullOffset(0);
      setStartY(0);
    }
  };

  const lastSeenText = useMemo(() => {
    const lastSeenDate = ensureDate(partnerData?.lastSeen);
    if (!lastSeenDate) return "";
    const diff = Math.floor((Date.now() - lastSeenDate.getTime()) / 60000);
    if (diff < 1) return "Just now";
    if (diff < 60) return `Last seen ${diff}m ago`;
    return `Last seen ${Math.floor(diff/60)}h ago`;
  }, [partnerData]);

  const handleDismissAlert = async (alertId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!userData?.householdId) return;
    await updateDoc(doc(db, 'households', userData.householdId, 'proactiveAlerts', alertId), {
      read: true
    });
  };

  const handleAlertClick = (alert: ProactiveAlert) => {
    // Map alert types to screens
    switch (alert.type) {
      case 'bill':
      case 'datenight':
        onNavigate('calendar');
        break;
      case 'grocery':
        onNavigate('grocery');
        break;
      case 'budget':
        onNavigate('finances');
        break;
      case 'chore':
        onNavigate('more'); // Assuming chores are in 'more' or have their own tab
        break;
      case 'savings':
        onNavigate('finances');
        break;
      case 'anniversary':
      case 'birthday':
        onNavigate('together');
        break;
    }
  };

  const handleMoodCheckIn = async (moodIndex: number) => {
    if (!userData?.householdId || !user) return;
    await saveMood(userData.householdId, user.uid, moodIndex + 1);
  };

  return (
    <div 
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
      style={{
        height: 'calc(100dvh - 84px)',
        overflowY: 'auto',
        overflowX: 'hidden',
        WebkitOverflowScrolling: 'touch',
        overscrollBehavior: 'contain',
        paddingBottom: 'calc(32px + env(safe-area-inset-bottom))',
        position: 'relative',
        background: '#FAF9F6' // Slightly brighter linen for better glass contrast
      }}
      className="no-scrollbar"
    >
      {/* Pull to Refresh Indicator */}
      <div 
        className="absolute top-0 left-0 right-0 flex justify-center z-50 pointer-events-none"
        style={{ height: pullOffset }}
      >
        <motion.div 
          animate={{ 
            y: pullOffset > 20 ? 40 : -40,
            opacity: pullOffset > 20 ? 1 : 0,
            rotate: pullOffset * 2,
            scale: isRefreshing ? [1, 1.1, 1] : pullOffset / REFRESH_THRESHOLD
          }}
          transition={isRefreshing ? { repeat: Infinity, duration: 1 } : { type: "spring", damping: 20 }}
          className="bg-white rounded-full p-2 shadow-xl border border-brass/20 text-brass"
        >
          <RefreshCw size={20} className={isRefreshing ? "animate-spin" : ""} />
        </motion.div>
      </div>

      {/* Mesh Background Overlay */}
      <div className="fixed inset-0 pointer-events-none z-0">
        <motion.div 
          animate={{
            background: [
              `radial-gradient(circle at 20% 20%, ${timeConfig.bg}88 0%, transparent 40%)`,
              `radial-gradient(circle at 80% 80%, ${timeConfig.bg}88 0%, transparent 40%)`,
              `radial-gradient(circle at 20% 20%, ${timeConfig.bg}88 0%, transparent 40%)`,
            ]
          }}
          transition={{ duration: 15, repeat: Infinity, ease: "linear" }}
          className="w-full h-full opacity-40 blur-[100px]"
        />
        <div 
          className="absolute inset-0 opacity-[0.03] mix-blend-overlay pointer-events-none" 
          style={{ backgroundImage: "var(--noise-url)" }} 
        />
      </div>

      {/* Section 1: Time-aware Header */}
      <motion.header
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        onClick={() => onNavigate('calendar')}
        className="relative z-10 w-full pt-16 pb-12 px-8 cursor-pointer"
      >
        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <h1 
              className="font-serif text-[44px] font-light leading-tight tracking-tight"
              style={{ color: timeConfig.dark ? "#F8F4EE" : "#1A1A1A" }}
            >
              {timeConfig.greeting}
            </h1>
            <p 
              className="font-outfit text-lg opacity-60"
              style={{ color: timeConfig.dark ? "#D4CEC4" : "#6B6560" }}
            >
              {userData?.displayName?.split(' ')[0] || "there"}
            </p>
          </div>
          <LivePulse active={isSyncing} />
        </div>
        
        <div className="mt-8 flex items-center gap-3">
          <div className="h-[1px] flex-1 bg-stone/20" />
          <p 
            className="font-outfit text-[11px] uppercase tracking-[3px] font-bold text-brass"
          >
            {format(currentTime, "EEEE, d MMM")}
          </p>
          <div className="h-[1px] flex-1 bg-stone/20" />
        </div>
      </motion.header>

      <div className="relative z-10 space-y-8 mt-2">
        {/* Coming Up Countdown */}
        {specialDates.length > 0 && (
          <Section delay={0.03}>
            <div className="flex items-center justify-between mb-4">
              <p className="font-outfit text-[11px] tracking-[2px] uppercase text-brass font-medium">
                Coming Up
              </p>
            </div>
            <div className="flex gap-4 overflow-x-auto pb-4 -mx-5 px-5 no-scrollbar snap-x">
              {specialDates.map((date) => (
                <motion.div
                  key={date.id}
                  onClick={() => fetchGiftSuggestions(date)}
                  whileTap={{ scale: 0.98 }}
                  className={`flex-shrink-0 w-[240px] bg-white/40 backdrop-blur-md border border-white/50 rounded-[28px] p-6 snap-start cursor-pointer relative overflow-hidden shadow-sm ${
                    date.daysUntil <= 1 ? 'border-l-[4px] border-l-rose-urgent' : 
                    date.daysUntil <= 7 ? 'border-l-[4px] border-l-brass' : ''
                  }`}
                >
                  {date.daysUntil <= 1 && (
                    <motion.div 
                      animate={{ 
                        boxShadow: [
                          "inset 0 0 0px rgba(196, 123, 106, 0)",
                          "inset 0 0 20px rgba(196, 123, 106, 0.2)",
                          "inset 0 0 0px rgba(196, 123, 106, 0)"
                        ]
                      }}
                      transition={{ duration: 2, repeat: Infinity }}
                      className="absolute inset-0 pointer-events-none"
                    />
                  )}
                  <div className="relative z-10">
                    <div className="flex justify-between items-start mb-2">
                      <span className="text-2xl">{date.emoji}</span>
                      <Gift size={16} className="text-stone" />
                    </div>
                    <div className="font-serif text-[48px] text-charcoal leading-none mb-1">
                      {date.daysUntil}
                    </div>
                    <div className="font-outfit text-[12px] text-warm-grey">
                      days until {date.name}
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </Section>
        )}

        {/* Anniversary Memory Card */}
        {isAnniversary && earliestMemory && (
          <Section delay={0.035}>
            <Card className="p-0 overflow-hidden border-brass/40">
              <div className="relative aspect-video">
                <img 
                  src={earliestMemory.imageUrl} 
                  alt="" 
                  className="w-full h-full object-cover"
                  referrerPolicy="no-referrer"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-charcoal/80 to-transparent flex flex-col justify-end p-6">
                  <p className="font-outfit text-[12px] text-white/70 uppercase tracking-widest mb-1">
                    On this day {differenceInYears(new Date(), earliestMemory.date?.toDate() || new Date())} years ago...
                  </p>
                  <p className="font-serif text-[20px] text-white italic">
                    {earliestMemory.caption || "Where it all began."}
                  </p>
                </div>
              </div>
            </Card>
          </Section>
        )}

        {/* Mood Check-in / Status */}
        <Section delay={0.04}>
          <AnimatePresence mode="wait">
            {!myMood ? (
              <motion.div
                key="check-in"
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.9, transition: { type: "spring", stiffness: 300, damping: 25 } }}
                className="glass-card border border-white/40 rounded-[28px] p-7 shadow-xl"
                style={{
                  background: "rgba(255, 255, 255, 0.45)",
                  backdropFilter: "blur(16px)",
                  boxShadow: "0 10px 40px rgba(0,0,0,0.05)"
                }}
              >
                <div className="flex items-center gap-2 mb-4">
                  <div className="w-1.5 h-1.5 rounded-full bg-brass animate-pulse" />
                  <p className="font-outfit text-[11px] uppercase tracking-[2px] text-warm-grey font-bold">Daily Check-in</p>
                </div>
                <div className="flex justify-between items-center bg-white/30 p-2 rounded-2xl border border-white/40">
                  {MOOD_EMOJIS.map((emoji, i) => (
                    <button
                      key={i}
                      onClick={() => handleMoodCheckIn(i)}
                      className="w-12 h-12 flex items-center justify-center text-2xl hover:bg-white/60 rounded-xl transition-all active:scale-90 hover:scale-110"
                    >
                      {emoji}
                    </button>
                  ))}
                </div>
              </motion.div>
            ) : (
              <motion.div
                key="mood-pill"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex justify-center"
              >
                <div 
                  className="bg-white/60 border border-white/80 rounded-full px-5 py-2 flex items-center gap-3 shadow-lg backdrop-blur-md"
                >
                  <div className="flex items-center gap-2">
                    <motion.span layoutId="my-mood-emoji" className="text-xl">{MOOD_EMOJIS[myMood.mood - 1]}</motion.span>
                    <div className="w-[1px] h-3 bg-stone/30" />
                    {partnerMood ? (
                      <motion.span layoutId="partner-mood-emoji" className="text-xl">{MOOD_EMOJIS[partnerMood.mood - 1]}</motion.span>
                    ) : (
                      <div className="w-6 h-6 rounded-full border border-stone/30 border-dashed flex items-center justify-center">
                        <Heart size={12} className="text-stone/40 animate-pulse" />
                      </div>
                    )}
                  </div>
                  <span className="font-outfit text-[11px] text-warm-grey font-bold uppercase tracking-wider">
                    {partnerMood ? "Synchronized" : "Vibe check"}
                  </span>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </Section>

        <Section delay={0.08}>
          <Card layoutId="partner-status" className="p-4 flex items-center justify-between group active:scale-[0.99] transition-transform">
            <div className="flex items-center gap-4">
              <div className="relative">
                <div className="absolute inset-0 bg-brass/20 rounded-full blur-md opacity-0 group-hover:opacity-100 transition-opacity" />
                <img 
                  src={partnerData?.photoURL || `https://ui-avatars.com/api/?name=${partnerData?.displayName || 'P'}&background=EDE8DF&color=1A1A1A`}
                  alt=""
                  className="relative w-14 h-14 rounded-full object-cover border-2 border-white shadow-md"
                  referrerPolicy="no-referrer"
                />
                <motion.div 
                  animate={partnerData?.isOnline ? { scale: [1, 1.2, 1] } : {}}
                  transition={{ repeat: Infinity, duration: 2 }}
                  className={`absolute -bottom-0.5 -right-0.5 w-4 h-4 rounded-full border-2 border-white ${partnerData?.isOnline ? 'bg-green-500' : 'bg-stone'}`}
                />
              </div>
              <div>
                <h2 className="font-serif text-[20px] text-charcoal leading-tight">
                  {partnerData?.displayName || "Partner"}
                </h2>
                <div className="flex items-center gap-1.5 mt-0.5">
                  <div className={`w-1.5 h-1.5 rounded-full ${partnerData?.isOnline ? 'bg-green-500' : 'bg-stone'}`} />
                  <p className="font-outfit text-[11px] text-warm-grey uppercase tracking-wider font-bold">
                    {partnerData?.isOnline ? "Active Now" : lastSeenText}
                  </p>
                </div>
              </div>
            </div>
            <div className="bg-stone/10 p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
              <ChevronRight size={16} className="text-stone" />
            </div>
          </Card>
        </Section>

        {/* Proactive Alerts Row */}
        {alerts.length > 0 && (
          <Section delay={0.12} className="!px-0">
            <div className="flex gap-3 overflow-x-auto no-scrollbar px-5 pb-2">
              {alerts.map((alert) => (
                <motion.div
                  key={alert.id}
                  layout
                  initial={{ opacity: 0, scale: 0.9, x: 20 }}
                  animate={{ opacity: 1, scale: 1, x: 0 }}
                  exit={{ opacity: 0, scale: 0.9, x: -20 }}
                  onClick={() => handleAlertClick(alert)}
                  className="relative min-w-[260px] flex-shrink-0 p-4 rounded-[16px] border flex items-center gap-4 cursor-pointer active:scale-[0.98] transition-transform shadow-sm"
                  style={{
                    background: alert.priority === 'high' ? '#F5E6E0' : '#EDE8DF',
                    borderColor: alert.priority === 'high' ? '#C47B6A' : '#D4CEC4'
                  }}
                >
                  <span className="text-2xl flex-shrink-0">
                    {alert.type === 'bill' && '💸'}
                    {alert.type === 'grocery' && '🛒'}
                    {alert.type === 'budget' && '📉'}
                    {alert.type === 'datenight' && '💝'}
                    {alert.type === 'chore' && '🧹'}
                    {alert.type === 'anniversary' && '🎉'}
                    {alert.type === 'birthday' && '🎂'}
                    {alert.type === 'savings' && '🎯'}
                  </span>
                  <p className="font-outfit text-[13px] text-[#1A1A1A] leading-[1.4] pr-4 flex-1">
                    {alert.message}
                  </p>
                  <button
                    onClick={(e) => handleDismissAlert(alert.id, e)}
                    className="absolute top-2 right-2 p-1 text-[#6B6560] hover:text-[#1A1A1A] transition-colors"
                  >
                    <X size={14} />
                  </button>
                </motion.div>
              ))}
            </div>
          </Section>
        )}

        {/* Section 3: Shared Dashboard Bento */}
        <Section delay={0.16}>
          <div className="grid grid-cols-12 gap-5 h-[240px]">
            {/* Main Tile: Next Event */}
            <Card 
              layoutId="next-event-card"
              onClick={() => onNavigate('calendar')}
              className="col-span-12 xs:col-span-7 p-6 flex flex-col justify-between group active:scale-[0.97] transition-all"
            >
              <div className="flex justify-between items-start">
                <div className="bg-brass/10 p-2 rounded-xl">
                  <Calendar size={20} className="text-brass group-hover:scale-110 transition-transform" />
                </div>
                <Sparkles size={16} className="text-brass/40 opacity-0 group-hover:opacity-100 transition-opacity" />
              </div>
              
              <div>
                <p className="font-outfit text-[10px] uppercase tracking-[2px] text-warm-grey mb-1 font-bold">Coming Up</p>
                {nextEvent ? (
                  <div className="space-y-1">
                    <h3 className="font-serif text-[22px] text-charcoal leading-tight line-clamp-2">{nextEvent.title}</h3>
                    <p className="font-outfit text-[14px] text-brass font-medium">
                      {ensureDate(nextEvent.date) ? format(ensureDate(nextEvent.date)!, "EEE, d MMM • h:mm a") : ""}
                    </p>
                  </div>
                ) : (
                  <EmptyState text="No upcoming events" />
                )}
              </div>
            </Card>

            <div className="col-span-12 xs:col-span-5 grid grid-cols-2 xs:grid-cols-1 gap-5">
              {/* Mini Tile: Groceries */}
              <Card 
                layoutId="grocery-mini-tile"
                onClick={() => onNavigate('grocery')}
                className="p-4 flex flex-col justify-center items-center text-center group"
              >
                <div className="relative">
                  <motion.span 
                    key={groceryCount}
                    initial={{ y: 10, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    className="block font-serif text-[32px] text-charcoal leading-none"
                  >
                    {groceryCount}
                  </motion.span>
                  <ShoppingCart size={14} className="absolute -right-4 top-0 text-stone opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>
                <span className="font-outfit text-[11px] text-warm-grey uppercase tracking-wider font-bold mt-1">Groceries</span>
              </Card>

              {/* Mini Tile: Spend */}
              <Card 
                layoutId="finance-mini-tile"
                onClick={() => onNavigate('finances')}
                className="p-4 flex flex-col justify-center items-center text-center group"
              >
                <div className="relative">
                   <motion.span 
                    key={monthlySpend}
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    className="block font-serif text-[24px] text-charcoal leading-none"
                  >
                    ${monthlySpend}
                  </motion.span>
                  <DollarSign size={14} className="absolute -right-4 top-0 text-stone opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>
                <span className="font-outfit text-[11px] text-warm-grey uppercase tracking-wider font-bold mt-1">This Month</span>
              </Card>
            </div>
          </div>
        </Section>

        {/* Section 4: Last Memory */}
        <Section delay={0.24}>
          <Card layoutId="last-memory" onClick={() => onNavigate('together')} className="group cursor-pointer p-0 border-white/40">
            <div className="aspect-[16/7] w-full relative bg-stone/10 overflow-hidden">
              {lastMemory ? (
                <>
                  <img 
                    src={lastMemory.imageUrl} 
                    alt="" 
                    className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
                    referrerPolicy="no-referrer"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-charcoal/60 via-transparent to-transparent opacity-60 group-hover:opacity-80 transition-opacity" />
                </>
              ) : (
                <div className="w-full h-full flex items-center justify-center">
                  <EmptyState text="Add your first memory together" />
                </div>
              )}
            </div>
            {lastMemory && (
              <div className="p-5 flex items-center justify-between">
                <p className="font-outfit text-[13px] text-warm-grey line-clamp-1 italic pr-4">
                  "{lastMemory.caption}"
                </p>
                <Sparkles size={14} className="text-brass/40" />
              </div>
            )}
          </Card>
        </Section>

        {/* Section 5: Partner's Last Note */}
        <Section delay={0.32}>
          <Card layoutId="last-note" className="p-8 relative min-h-[160px] flex flex-col justify-center border-white/40">
            <span className="absolute top-4 left-6 font-serif text-[100px] text-brass/10 leading-none select-none italic">
              “
            </span>
            <div className="relative z-10 space-y-4">
              {lastNote ? (
                <>
                  <p className="font-serif italic text-[20px] text-charcoal leading-relaxed tracking-tight">
                    {lastNote.text}
                  </p>
                  <div className="flex items-center gap-2">
                    <div className="h-[1px] w-6 bg-brass/30" />
                    <p className="font-outfit text-[11px] text-brass uppercase tracking-widest font-bold">
                      {lastNote.authorName || partnerData?.displayName || "Partner"}
                    </p>
                  </div>
                </>
              ) : (
                <EmptyState text="Nothing shared yet — surprise them with a note" />
              )}
            </div>
          </Card>
        </Section>

        {/* Section 6: Relationship Insights */}
        <Section delay={0.4} className="pb-12">
            <div className="mb-4 flex items-center justify-between">
              <p className="font-outfit text-[11px] tracking-[2px] uppercase text-brass font-bold">
                Daily Insights
              </p>
              <div className="h-[1px] flex-1 bg-stone/10 ml-4" />
            </div>

            <AnimatePresence mode="wait">
              {loadingInsights ? (
                <motion.div 
                  key="loading"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="space-y-4"
                >
                  {[1, 2].map(i => (
                    <div key={i} className="bg-white/30 border border-white/40 rounded-[24px] p-6 animate-pulse">
                      <div className="flex gap-4">
                        <div className="w-12 h-12 bg-stone/10 rounded-2xl" />
                        <div className="flex-1 space-y-3">
                          <div className="h-4 bg-stone/10 rounded w-1/3" />
                          <div className="h-3 bg-stone/10 rounded w-full" />
                        </div>
                      </div>
                    </div>
                  ))}
                </motion.div>
              ) : insights && insights.length > 0 ? (
                <motion.div 
                  key="insights"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="space-y-4"
                >
                  {insights.map((insight, i) => (
                    <motion.div 
                      key={i} 
                      whileHover={{ y: -4, backgroundColor: "rgba(255, 255, 255, 0.5)" }}
                      className="bg-white/40 border border-white/50 rounded-[24px] p-6 shadow-sm backdrop-blur-sm transition-colors"
                    >
                      <div className="flex items-start gap-4">
                        <div className="w-12 h-12 flex items-center justify-center bg-white/60 rounded-2xl shadow-inner text-2xl flex-shrink-0">
                          {insight.emoji}
                        </div>
                        <div className="space-y-1.5 flex-1 pt-1">
                          <h3 className="font-serif text-[18px] text-[#1A1A1A] leading-tight font-bold">
                            {insight.title}
                          </h3>
                          <p className="font-outfit text-[13px] text-[#6B6560] leading-[1.6]">
                            {insight.body}
                          </p>
                          {insight.action && (
                            <div className="inline-flex items-center gap-2 mt-4 text-brass group cursor-pointer hover:text-charcoal transition-colors">
                              <p className="font-outfit text-[11px] uppercase tracking-wider font-bold italic">
                                {insight.action}
                              </p>
                              <ChevronRight size={12} className="group-hover:translate-x-1 transition-transform" />
                            </div>
                          )}
                        </div>
                      </div>
                    </motion.div>
                  ))}
                </motion.div>
              ) : (
                <motion.div 
                  key="empty"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="text-center py-10 bg-stone/5 rounded-[24px] border border-dashed border-stone/20"
                >
                  <p className="font-outfit text-[13px] text-[#6B6560] italic">
                    Building insights based on your shared activity...
                  </p>
                </motion.div>
              )}
            </AnimatePresence>
          </Section>

          {/* Section 7: Weekly Summary */}
          {(weeklySummary || loadingSummary) && isSunday(new Date()) && (
            <Section delay={0.48} className="pb-12">
              <Card className="p-7 relative overflow-hidden bg-gradient-to-br from-brass/5 to-parchment/30 border-white/60 rounded-[32px]">
                <div className="absolute -top-10 -right-10 w-40 h-40 bg-brass/5 rounded-full blur-[60px]" />
                
                <button 
                  onClick={handleDismissSummary}
                  className="absolute top-5 right-5 p-2 text-warm-grey/60 hover:text-charcoal transition-colors z-10 hover:bg-white/40 rounded-full"
                >
                  <X size={16} />
                </button>

                <div className="flex items-center justify-between mb-8">
                  <div>
                    <p className="font-outfit text-[10px] tracking-[3px] uppercase text-brass font-black mb-1">Weekly Digest</p>
                    <p className="font-serif text-[18px] text-charcoal italic">
                      {weeklySummary ? `${format(weeklySummary.weekStart.toDate(), "MMM d")} — ${format(weeklySummary.weekEnd.toDate(), "MMM d")}` : "..."}
                    </p>
                  </div>
                </div>

                {loadingSummary ? (
                  <div className="space-y-6">
                    <div className="flex gap-3">
                      {[1, 2, 3].map(i => (
                        <div key={i} className="h-9 w-24 bg-white/40 rounded-full animate-pulse flex-shrink-0" />
                      ))}
                    </div>
                    <div className="space-y-3">
                      <div className="h-4 bg-charcoal/5 rounded-full w-full animate-pulse" />
                      <div className="h-4 bg-charcoal/5 rounded-full w-4/6 animate-pulse" />
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar snap-x">
                      {[
                        { icon: "💰", val: `$${weeklySummary?.stats.spent.toFixed(0)}`, label: "Spent" },
                        { icon: "✅", val: Object.values(weeklySummary?.stats.choresCompleted || {}).reduce((a, b) => a + b, 0), label: "Chores" },
                        { icon: "📸", val: weeklySummary?.stats.memoriesCount, label: "Memories" },
                        { icon: "🛒", val: weeklySummary?.stats.groceriesCompleted, label: "Items" }
                      ].map((stat, i) => (
                        <motion.div 
                          key={i}
                          initial={{ opacity: 0, scale: 0.8 }}
                          animate={{ opacity: 1, scale: 1 }}
                          transition={{ delay: 0.5 + (i * 0.1) }}
                          className="bg-white/60 px-5 py-2.5 rounded-2xl flex flex-col items-center gap-0.5 flex-shrink-0 snap-start shadow-sm border border-white/80"
                        >
                          <span className="text-xl mb-1">{stat.icon}</span>
                          <span className="font-serif text-[16px] text-charcoal font-bold">{stat.val}</span>
                          <span className="font-outfit text-[9px] uppercase tracking-tighter text-warm-grey font-bold">{stat.label}</span>
                        </motion.div>
                      ))}
                    </div>

                    <p className="font-serif italic text-[18px] text-charcoal/90 leading-relaxed mt-4 bg-white/30 p-5 rounded-2xl border border-white/30">
                      {weeklySummary?.narrative || "Start using OurSpace this week and we'll write your first weekly story on Sunday"}
                    </p>
                  </>
                )}
              </Card>
          </Section>
        )}
      </div>
      {/* Gift Suggestions Sheet */}
      <BottomSheet 
        isOpen={!!selectedDateForGifts} 
        onClose={() => setSelectedDateForGifts(null)}
        title={`${selectedDateForGifts?.name} Gift Ideas`}
      >
        <div className="space-y-4 pb-8">
          {loadingGifts ? (
            <div className="flex flex-col items-center py-12 space-y-4">
              <div className="w-8 h-8 border-2 border-brass border-t-transparent rounded-full animate-spin" />
              <p className="font-outfit text-sm text-warm-grey italic">Gemini is finding thoughtful ideas...</p>
            </div>
          ) : (
            giftSuggestions.map((gift, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.1 }}
                className="bg-parchment border border-stone rounded-[20px] p-5 flex gap-4"
              >
                <span className="text-3xl flex-shrink-0">{gift.emoji}</span>
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start mb-1">
                    <h3 className="font-serif text-[16px] text-charcoal leading-tight">{gift.name}</h3>
                    <div className="bg-brass/10 px-2 py-0.5 rounded-full">
                      <span className="font-outfit text-[10px] text-brass font-bold uppercase">{gift.estimatedCost}</span>
                    </div>
                  </div>
                  <p className="font-outfit text-[13px] text-warm-grey leading-relaxed">
                    {gift.description}
                  </p>
                </div>
              </motion.div>
            ))
          )}
        </div>
      </BottomSheet>

      {/* Birthday Animation Overlay */}
      {isPartnerBirthday && (
        <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
          {[...Array(15)].map((_, i) => (
            <motion.div
              key={i}
              initial={{ y: "110vh", x: `${Math.random() * 100}vw`, opacity: 0 }}
              animate={{ 
                y: "-10vh", 
                opacity: [0, 0.4, 0],
                x: `${Math.random() * 100}vw`
              }}
              transition={{ 
                duration: 10 + Math.random() * 10, 
                repeat: Infinity, 
                delay: Math.random() * 10,
                ease: "linear"
              }}
              className="absolute w-2 h-2 rounded-full bg-brass/30 blur-sm"
            />
          ))}
        </div>
      )}
    </div>
  );
}

/**
 * OurSpace — Bank Import Flow
 * Supports CSV (CommBank, NAB, ANZ, Westpac, generic) and PDF (Gemini Vision)
 */

import { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { Upload, X, Check, AlertTriangle, ChevronRight, FileText, Loader2 } from 'lucide-react';
import { parseCSV, parsePDF, checkDuplicate, BankTransaction } from '../../lib/bankParsers';
import { useAuth } from '../AuthWrapper';
import { db } from '../../firebase';
import { collection, addDoc, serverTimestamp, getDocs, query, orderBy, limit } from 'firebase/firestore';
import { BUILT_IN_CATEGORIES, getCategoryDef } from '../../design/tokens';
import { categorizeItem } from '../../lib/categorization';
import { formatAUD } from '../../lib/cashflow';
import { SPRING_DEFAULT, SPRING_BOUNCY, staggerContainer, staggerItem } from '../../lib/motion';

interface Props {
  onClose: () => void;
  onImported: (count: number) => void;
}

type Step = 'upload' | 'preview' | 'importing' | 'done';

interface PreviewTransaction extends BankTransaction {
  category: string;
  categoryConfidence: number;
  selected: boolean;
  isDuplicate: boolean;
  matchedMerchant?: string;
}

export default function BankImportFlow({ onClose, onImported }: Props) {
  const { householdId, user } = useAuth();
  const [step, setStep] = useState<Step>('upload');
  const [transactions, setTransactions] = useState<PreviewTransaction[]>([]);
  const [importing, setImporting] = useState(false);
  const [importedCount, setImportedCount] = useState(0);
  const [error, setError] = useState('');
  const [activeFilter, setActiveFilter] = useState<'all' | 'expenses' | 'income' | 'duplicates'>('all');
  const [processingProgress, setProcessingProgress] = useState(0);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleFile = async (file: File) => {
    if (!householdId) return;
    setError('');
    setStep('preview');
    setProcessingProgress(0);

    try {
      let raw: BankTransaction[] = [];

      if (file.name.toLowerCase().endsWith('.pdf')) {
        setProcessingProgress(10);
        raw = await parsePDF(file);
        setProcessingProgress(50);
      } else {
        const text = await file.text();
        raw = parseCSV(text, file.name);
        setProcessingProgress(30);
      }

      // Fetch existing expenses for duplicate check
      const expSnap = await getDocs(
        query(collection(db, `households/${householdId}/expenses`), orderBy('date', 'desc'), limit(200))
      );
      const existingExpenses = expSnap.docs.map(d => ({
        id: d.id,
        merchantName: d.data().merchantName || '',
        total: d.data().total || 0,
        date: d.data().date?.toDate() || new Date(),
      }));

      setProcessingProgress(60);

      // Categorize + duplicate check
      const previews: PreviewTransaction[] = await Promise.all(
        raw.slice(0, 500).map(async (tx, i) => {
          const catResult = tx.type === 'debit'
            ? await categorizeItem(tx.cleanDescription, tx.cleanDescription, householdId)
            : { cat: 'income', confidence: 1.0 };

          const dupCheck = tx.type === 'debit'
            ? checkDuplicate(tx, existingExpenses)
            : { isDuplicate: false };

          setProcessingProgress(60 + (i / raw.length) * 35);

          return {
            ...tx,
            category: catResult.cat,
            categoryConfidence: catResult.confidence,
            selected: !dupCheck.isDuplicate,
            isDuplicate: dupCheck.isDuplicate,
            matchedMerchant: dupCheck.matchedMerchant,
          };
        })
      );

      setProcessingProgress(100);
      setTransactions(previews);
    } catch (e: any) {
      setError(e.message || 'Failed to parse file');
      setStep('upload');
    }
  };

  const handleImport = async () => {
    if (!householdId || !user) return;
    setImporting(true);
    setStep('importing');

    const toImport = transactions.filter(t => t.selected);
    let count = 0;

    for (const tx of toImport) {
      try {
        const coll = tx.type === 'credit'
          ? `households/${householdId}/bankTransactions`
          : `households/${householdId}/expenses`;

        await addDoc(collection(db, coll), {
          merchantName: tx.cleanDescription,
          description: tx.description,
          amount: Math.abs(tx.amount),
          total: Math.abs(tx.amount),
          category: tx.category,
          date: tx.date,
          type: tx.type,
          incomeType: tx.incomeType || null,
          bankSource: tx.bankSource,
          importedAt: serverTimestamp(),
          importedBy: user.uid,
          source: 'bank_import',
          lineItems: [],
        });
        count++;
      } catch (e) {
        console.warn('Failed to import transaction:', e);
      }
    }

    setImportedCount(count);
    setStep('done');
    onImported(count);
  };

  const filtered = transactions.filter(t => {
    if (activeFilter === 'expenses')   return t.type === 'debit' && !t.isDuplicate;
    if (activeFilter === 'income')     return t.type === 'credit';
    if (activeFilter === 'duplicates') return t.isDuplicate;
    return true;
  });

  const stats = {
    expenses:   transactions.filter(t => t.type === 'debit').length,
    income:     transactions.filter(t => t.type === 'credit').length,
    duplicates: transactions.filter(t => t.isDuplicate).length,
    selected:   transactions.filter(t => t.selected).length,
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[9999] bg-[#1A1A1A]/50 backdrop-blur-sm flex items-end"
    >
      <motion.div
        initial={{ y: '100%' }}
        animate={{ y: 0 }}
        exit={{ y: '100%' }}
        transition={SPRING_DEFAULT}
        className="bg-[#F8F4EE] rounded-t-[28px] w-full max-h-[92dvh] flex flex-col overflow-hidden"
      >
        {/* Header */}
        <div className="px-6 pt-6 pb-4 flex items-center justify-between flex-shrink-0">
          <div>
            <h2 className="font-serif text-[22px] text-[#1A1A1A]">Import Bank Statement</h2>
            <p className="font-outfit text-[13px] text-[#6B6560] mt-0.5">CommBank, NAB, ANZ, Westpac + more</p>
          </div>
          <button onClick={onClose} className="w-10 h-10 rounded-full bg-[#EDE8DF] flex items-center justify-center">
            <X size={18} className="text-[#1A1A1A]" />
          </button>
        </div>

        {/* Drag handle */}
        <div className="w-10 h-1 bg-[#D4CEC4] rounded-full mx-auto mb-2 flex-shrink-0" />

        <div className="flex-1 overflow-y-auto px-6 pb-8">
          <AnimatePresence mode="wait">

            {/* STEP: UPLOAD */}
            {step === 'upload' && (
              <motion.div key="upload" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                <input
                  ref={fileRef}
                  type="file"
                  className="hidden"
                  accept=".csv,.pdf,.ofx,.qif"
                  onChange={e => { const f = e.target.files?.[0]; if (f) handleFile(f); }}
                />

                <motion.div
                  whileTap={{ scale: 0.98 }}
                  onClick={() => fileRef.current?.click()}
                  className="border-2 border-dashed border-[#D4CEC4] rounded-2xl p-12 flex flex-col items-center justify-center cursor-pointer hover:border-[#B8955A] hover:bg-[#B8955A]/5 transition-colors mt-4"
                >
                  <div className="w-16 h-16 rounded-full bg-[#EDE8DF] flex items-center justify-center mb-4">
                    <Upload size={28} className="text-[#B8955A]" />
                  </div>
                  <h3 className="font-serif text-[18px] text-[#1A1A1A] mb-2">Choose file</h3>
                  <p className="font-outfit text-[13px] text-[#6B6560] text-center">
                    CSV or PDF bank statement<br />CommBank · NAB · ANZ · Westpac · Macquarie · ING
                  </p>
                </motion.div>

                {error && (
                  <div className="mt-4 p-4 bg-[#FDF0EE] border border-[#E8A090] rounded-2xl flex items-center gap-3">
                    <AlertTriangle size={16} className="text-[#C47B6A] flex-shrink-0" />
                    <p className="font-outfit text-[13px] text-[#C47B6A]">{error}</p>
                  </div>
                )}

                {/* Supported formats */}
                <div className="mt-8 space-y-2">
                  <p className="font-outfit text-[11px] uppercase tracking-widest text-[#B8955A] mb-3">Supported formats</p>
                  {['CommBank CSV (Date, Amount, Description)', 'NAB CSV (all formats)', 'ANZ CSV', 'Westpac CSV', 'Any bank PDF statement (AI-powered)', 'Generic CSV with date + amount'].map(f => (
                    <div key={f} className="flex items-center gap-2">
                      <Check size={12} className="text-[#4CAF50]" />
                      <span className="font-outfit text-[13px] text-[#6B6560]">{f}</span>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}

            {/* STEP: PREVIEW (loading) */}
            {step === 'preview' && transactions.length === 0 && (
              <motion.div key="loading" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex flex-col items-center justify-center pt-16">
                <div className="w-16 h-16 rounded-full bg-[#EDE8DF] flex items-center justify-center mb-6">
                  <Loader2 size={28} className="text-[#B8955A] animate-spin" />
                </div>
                <h3 className="font-serif text-[20px] text-[#1A1A1A] mb-2">Reading your statement</h3>
                <p className="font-outfit text-[13px] text-[#6B6560] mb-6">Categorizing transactions...</p>
                <div className="w-full h-1.5 bg-[#D4CEC4] rounded-full overflow-hidden">
                  <motion.div
                    className="h-full bg-[#B8955A] rounded-full"
                    initial={{ width: 0 }}
                    animate={{ width: `${processingProgress}%` }}
                    transition={{ duration: 0.5, ease: 'easeOut' }}
                  />
                </div>
                <p className="font-outfit text-[12px] text-[#B8955A] mt-2">{Math.round(processingProgress)}%</p>
              </motion.div>
            )}

            {/* STEP: PREVIEW (results) */}
            {step === 'preview' && transactions.length > 0 && (
              <motion.div key="preview" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
                {/* Summary */}
                <div className="bg-[#EDE8DF] rounded-2xl p-4 mb-4 mt-2">
                  <p className="font-serif text-[18px] text-[#1A1A1A]">
                    Found <span className="text-[#B8955A]">{transactions.length}</span> transactions
                  </p>
                  <div className="flex gap-4 mt-2">
                    <span className="font-outfit text-[12px] text-[#4CAF50]">{stats.income} income</span>
                    <span className="font-outfit text-[12px] text-[#C47B6A]">{stats.expenses} expenses</span>
                    {stats.duplicates > 0 && (
                      <span className="font-outfit text-[12px] text-[#FF9800]">{stats.duplicates} duplicates</span>
                    )}
                  </div>
                </div>

                {/* Filter tabs */}
                <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar pb-1">
                  {([
                    { key: 'all', label: `All (${transactions.length})` },
                    { key: 'expenses', label: `Expenses (${stats.expenses})` },
                    { key: 'income', label: `Income (${stats.income})` },
                    ...(stats.duplicates > 0 ? [{ key: 'duplicates', label: `Duplicates (${stats.duplicates})` }] : []),
                  ] as const).map(tab => (
                    <button
                      key={tab.key}
                      onClick={() => setActiveFilter(tab.key as any)}
                      className={`px-4 py-2 rounded-full font-outfit text-[12px] whitespace-nowrap transition-colors ${
                        activeFilter === tab.key
                          ? 'bg-[#1A1A1A] text-white'
                          : 'bg-[#EDE8DF] text-[#6B6560]'
                      }`}
                    >
                      {tab.label}
                    </button>
                  ))}
                </div>

                {/* Select all */}
                <div className="flex items-center justify-between mb-3">
                  <button
                    className="font-outfit text-[12px] text-[#B8955A]"
                    onClick={() => setTransactions(prev => prev.map(t => ({ ...t, selected: true })))}
                  >
                    Select all
                  </button>
                  <button
                    className="font-outfit text-[12px] text-[#6B6560]"
                    onClick={() => setTransactions(prev => prev.map(t => ({ ...t, selected: false })))}
                  >
                    Deselect all
                  </button>
                </div>

                {/* Transaction list */}
                <div className="space-y-2 mb-6">
                  {filtered.map(tx => {
                    const catDef = getCategoryDef(tx.category);
                    return (
                      <motion.div
                        key={tx.id}
                        layout
                        className={`flex items-center gap-3 p-3 rounded-2xl border transition-colors cursor-pointer ${
                          tx.selected
                            ? 'bg-[#EDE8DF] border-[#D4CEC4]'
                            : 'bg-[#F8F4EE] border-[#D4CEC4]/50 opacity-50'
                        } ${tx.isDuplicate ? 'border-[#FF9800]/50' : ''}`}
                        onClick={() => setTransactions(prev =>
                          prev.map(t => t.id === tx.id ? { ...t, selected: !t.selected } : t)
                        )}
                      >
                        {/* Category emoji */}
                        <div
                          className="w-9 h-9 rounded-full flex items-center justify-center text-[16px] flex-shrink-0"
                          style={{ background: catDef.light }}
                        >
                          {tx.type === 'credit' ? '💰' : catDef.emoji}
                        </div>

                        {/* Info */}
                        <div className="flex-1 min-w-0">
                          <p className="font-outfit text-[13px] text-[#1A1A1A] truncate font-medium">
                            {tx.cleanDescription || tx.description}
                          </p>
                          <p className="font-outfit text-[11px] text-[#6B6560]">
                            {tx.date.toLocaleDateString('en-AU', { day: 'numeric', month: 'short' })}
                            {tx.isDuplicate && <span className="ml-2 text-[#FF9800]">⚠ Possibly already scanned</span>}
                          </p>
                        </div>

                        {/* Amount */}
                        <p className={`font-serif text-[15px] font-light flex-shrink-0 ${
                          tx.type === 'credit' ? 'text-[#4CAF50]' : 'text-[#1A1A1A]'
                        }`}>
                          {tx.type === 'credit' ? '+' : ''}{formatAUD(Math.abs(tx.amount))}
                        </p>

                        {/* Checkbox */}
                        <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                          tx.selected ? 'bg-[#B8955A] border-[#B8955A]' : 'border-[#D4CEC4]'
                        }`}>
                          {tx.selected && <Check size={10} className="text-white" />}
                        </div>
                      </motion.div>
                    );
                  })}
                </div>

                {/* Import button */}
                <motion.button
                  whileTap={{ scale: 0.97 }}
                  onClick={handleImport}
                  disabled={stats.selected === 0}
                  className={`w-full h-14 rounded-full font-outfit font-semibold text-[15px] transition-all ${
                    stats.selected > 0
                      ? 'bg-[#1A1A1A] text-white shadow-lg'
                      : 'bg-[#D4CEC4] text-white cursor-not-allowed'
                  }`}
                >
                  Import {stats.selected} transaction{stats.selected !== 1 ? 's' : ''}
                </motion.button>
              </motion.div>
            )}

            {/* STEP: IMPORTING */}
            {step === 'importing' && (
              <motion.div key="importing" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex flex-col items-center justify-center pt-16">
                <Loader2 size={48} className="text-[#B8955A] animate-spin mb-6" />
                <h3 className="font-serif text-[20px] text-[#1A1A1A] mb-2">Importing...</h3>
                <p className="font-outfit text-[13px] text-[#6B6560]">Saving {stats.selected} transactions</p>
              </motion.div>
            )}

            {/* STEP: DONE */}
            {step === 'done' && (
              <motion.div key="done" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={SPRING_BOUNCY} className="flex flex-col items-center justify-center pt-12 text-center">
                <div className="w-20 h-20 rounded-full bg-[#E8F5E9] flex items-center justify-center mb-6">
                  <Check size={36} className="text-[#4CAF50]" />
                </div>
                <h3 className="font-serif text-[24px] text-[#1A1A1A] mb-2">Imported!</h3>
                <p className="font-outfit text-[15px] text-[#6B6560] mb-8">
                  {importedCount} transactions added to your finances
                </p>
                <button
                  onClick={onClose}
                  className="w-full h-14 rounded-full bg-[#1A1A1A] text-white font-outfit font-semibold text-[15px]"
                >
                  Done
                </button>
              </motion.div>
            )}

          </AnimatePresence>
        </div>
      </motion.div>
    </motion.div>
  );
}

import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "motion/react";
import { 
  doc, 
  setDoc, 
  getDoc,
  onSnapshot, 
  collection, 
  query, 
  where, 
  getDocs, 
  updateDoc, 
  arrayUnion,
  serverTimestamp,
  deleteDoc
} from "firebase/firestore";
import { db, auth } from "../../firebase";
import { useAuth } from "../AuthWrapper";

interface OnboardingStep3Props {
  onNext: () => void;
}

const spring = { type: "spring" as const, stiffness: 280, damping: 22 };

const fadeUp = (delay = 0) => ({
  initial: { opacity: 0, y: 48, filter: "blur(4px)" },
  animate: { opacity: 1, y: 0, filter: "blur(0px)" },
  transition: { ...spring, delay }
});

export default function OnboardingStep3({ onNext }: OnboardingStep3Props) {
  const { user } = useAuth();
  const [selectedMode, setSelectedMode] = useState<"create" | "join" | null>(null);
  const [inviteCode, setInviteCode] = useState("");
  const [joinCode, setJoinCode] = useState(["", "", "", "", "", ""]);
  const [error, setError] = useState("");
  const [isJoining, setIsJoining] = useState(false);
  const [isShaking, setIsShaking] = useState(false);
  const [partnerEmail, setPartnerEmail] = useState("");
  const [isSendingInvite, setIsSendingInvite] = useState(false);
  const [inviteSent, setInviteSent] = useState(false);
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  // Generate code and setup household for CREATE mode
  useEffect(() => {
    if (selectedMode === "create" && !inviteCode && user) {
      const code = Math.floor(100000 + Math.random() * 900000).toString();
      setInviteCode(code);

      const setupHousehold = async () => {
        const householdId = `h_${user.uid}_${Date.now()}`;
        
        // 1. Create household
        await setDoc(doc(db, "households", householdId), {
          id: householdId,
          memberIds: [user.uid],
          createdAt: serverTimestamp(),
          createdBy: user.uid
        });

        // 2. Create invite code mapping
        await setDoc(doc(db, "inviteCodes", code), {
          code,
          householdId,
          createdBy: user.uid,
          createdAt: serverTimestamp()
        });

        // 3. Update current user's householdId
        await updateDoc(doc(db, "users", user.uid), {
          householdId: householdId
        });
      };

      setupHousehold();
    }
  }, [selectedMode, user, inviteCode]);

  // Listen for partner joining in CREATE mode
  useEffect(() => {
    if (selectedMode === "create" && inviteCode && user) {
      // Let's find the householdId we just created
      const findAndListen = async () => {
        try {
          const userDoc = await getDoc(doc(db, "users", user.uid));
          const householdId = userDoc.data()?.householdId;
          
          if (householdId) {
            return onSnapshot(doc(db, "households", householdId), (snapshot) => {
              const data = snapshot.data();
              if (data && data.memberIds.length > 1) {
                // Partner joined!
                onNext();
              }
            }, (err) => {
              console.error("Error listening to household:", err);
            });
          }
        } catch (err) {
          console.error("Error in findAndListen:", err);
        }
      };

      let unsubscribe: (() => void) | undefined;
      findAndListen().then(unsub => { unsubscribe = unsub; });
      return () => { unsubscribe?.(); };
    }
  }, [selectedMode, inviteCode, user, onNext]);

  const handleJoinCodeChange = (index: number, value: string) => {
    if (value.length > 1) value = value[0];
    if (!/^\d*$/.test(value)) return;

    const newCode = [...joinCode];
    newCode[index] = value;
    setJoinCode(newCode);
    setError("");

    // Auto-focus next
    if (value && index < 5) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent) => {
    if (e.key === "Backspace" && !joinCode[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
  };

  const handleJoin = async () => {
    const code = joinCode.join("");
    if (code.length !== 6 || !user) return;

    setIsJoining(true);
    setError("");

    try {
      const codeDoc = await getDoc(doc(db, "inviteCodes", code));
      
      if (!codeDoc.exists()) {
        throw new Error("Invalid invite code");
      }

      const inviteData = codeDoc.data();
      const householdId = inviteData.householdId;

      // Add user to household
      await updateDoc(doc(db, "households", householdId), {
        memberIds: arrayUnion(user.uid)
      });

      // Update user's householdId
      await updateDoc(doc(db, "users", user.uid), {
        householdId: householdId
      });

      // Delete invite code (one-time use)
      await deleteDoc(doc(db, "inviteCodes", code));

      onNext();
    } catch (err: any) {
      setError(err.message || "Something went wrong");
      setIsShaking(true);
      setTimeout(() => setIsShaking(false), 400);
    } finally {
      setIsJoining(false);
    }
  };

  const copyCode = () => {
    navigator.clipboard.writeText(inviteCode);
  };

  const shareWhatsApp = () => {
    const text = `Join me on OurSpace! Use my invite code: ${inviteCode}`;
    window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, "_blank");
  };

  const sendEmailInvite = async () => {
    if (!user || !partnerEmail || !inviteCode) return;
    setIsSendingInvite(true);
    try {
      // Find the household Id we just created
      const userDoc = await getDoc(doc(db, "users", user.uid));
      const householdId = userDoc.data()?.householdId;
      if (!householdId) throw new Error("No household found");

      await setDoc(doc(collection(db, "emailInvites")), {
        email: partnerEmail.toLowerCase().trim(),
        fromUid: user.uid,
        fromName: user.displayName || 'Your Partner',
        householdId: householdId,
        createdAt: serverTimestamp()
      });
      setInviteSent(true);
      setPartnerEmail("");
      setTimeout(() => setInviteSent(false), 3000);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSendingInvite(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: "100%" }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: "-40px" }}
      transition={{ type: "spring", stiffness: 280, damping: 26 }}
      style={{
        minHeight: "100dvh",
        background: "#F8F4EE",
        display: "flex",
        flexDirection: "column",
        justifyContent: "space-between",
        padding: "80px 32px 60px"
      }}
    >
      <div>
        <motion.p {...fadeUp(0)} style={{
          fontFamily: "'Outfit', sans-serif",
          fontSize: "13px",
          letterSpacing: "2px",
          textTransform: "uppercase",
          color: "#B8955A",
          margin: "0 0 20px"
        }}>
          Step 3 of 4
        </motion.p>

        <motion.h1 {...fadeUp(0.1)} style={{
          fontFamily: "'Fraunces', serif",
          fontSize: "clamp(36px, 10vw, 52px)",
          fontWeight: 300,
          lineHeight: 1.1,
          color: "#1A1A1A",
          margin: "0 0 16px",
          letterSpacing: "-1.5px"
        }}>
          Link your<br/>partner
        </motion.h1>

        <motion.p {...fadeUp(0.2)} style={{
          fontFamily: "'Outfit', sans-serif",
          fontSize: "16px",
          color: "#6B6560",
          margin: "0 0 40px",
          lineHeight: 1.6
        }}>
          Choose how you want to connect
        </motion.p>

        {/* Option cards */}
        <motion.div {...fadeUp(0.3)} style={{
          display: "flex",
          flexDirection: "column",
          gap: "16px"
        }}>
          {/* Card 1 — Create household */}
          <motion.button
            whileTap={{ scale: 0.97 }}
            onClick={() => setSelectedMode("create")}
            style={{
              background: selectedMode === "create" ? "#1A1A1A" : "#EDE8DF",
              border: "1px solid #D4CEC4",
              borderRadius: "20px",
              padding: "24px",
              textAlign: "left",
              cursor: "pointer",
              transition: "background 0.3s ease"
            }}
          >
            <p style={{
              fontFamily: "'Fraunces', serif",
              fontSize: "20px",
              fontWeight: 400,
              color: selectedMode === "create" ? "#FFFFFF" : "#1A1A1A",
              margin: "0 0 6px"
            }}>
              Invite my partner
            </p>
            <p style={{
              fontFamily: "'Outfit', sans-serif",
              fontSize: "14px",
              color: selectedMode === "create" ? "#D4CEC4" : "#6B6560",
              margin: 0
            }}>
              Generate a code and share it
            </p>
          </motion.button>

          {/* Card 2 — Join household */}
          <motion.button
            whileTap={{ scale: 0.97 }}
            onClick={() => setSelectedMode("join")}
            style={{
              background: selectedMode === "join" ? "#1A1A1A" : "#EDE8DF",
              border: "1px solid #D4CEC4",
              borderRadius: "20px",
              padding: "24px",
              textAlign: "left",
              cursor: "pointer",
              transition: "background 0.3s ease"
            }}
          >
            <p style={{
              fontFamily: "'Fraunces', serif",
              fontSize: "20px",
              fontWeight: 400,
              color: selectedMode === "join" ? "#FFFFFF" : "#1A1A1A",
              margin: "0 0 6px"
            }}>
              I have a code
            </p>
            <p style={{
              fontFamily: "'Outfit', sans-serif",
              fontSize: "14px",
              color: selectedMode === "join" ? "#D4CEC4" : "#6B6560",
              margin: 0
            }}>
              Enter a code from your partner
            </p>
          </motion.button>
        </motion.div>

        <AnimatePresence mode="wait">
          {selectedMode === "create" && (
            <motion.div
              key="create-ui"
              initial={{ opacity: 0, y: 24, filter: "blur(4px)" }}
              animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
              exit={{ opacity: 0, y: -16 }}
              transition={spring}
              style={{
                marginTop: "24px",
                background: "#EDE8DF",
                border: "1px solid #D4CEC4",
                borderRadius: "20px",
                padding: "24px",
                textAlign: "center"
              }}
            >
              <p style={{
                fontFamily: "'Outfit', sans-serif",
                fontSize: "13px",
                letterSpacing: "2px",
                textTransform: "uppercase",
                color: "#B8955A",
                margin: "0 0 12px"
              }}>
                Your invite code
              </p>
              <p style={{
                fontFamily: "'Fraunces', serif",
                fontSize: "48px",
                fontWeight: 400,
                color: "#1A1A1A",
                letterSpacing: "8px",
                margin: "0 0 16px"
              }}>
                {inviteCode}
              </p>
              <div style={{ display: "flex", gap: "12px", justifyContent: "center" }}>
                <motion.button
                  whileTap={{ scale: 0.96 }}
                  onClick={copyCode}
                  style={{
                    background: "#1A1A1A",
                    color: "#FFFFFF",
                    border: "none",
                    borderRadius: "999px",
                    padding: "12px 28px",
                    fontFamily: "'Outfit', sans-serif",
                    fontSize: "14px",
                    cursor: "pointer"
                  }}
                >
                  Copy code
                </motion.button>
                <motion.button
                  whileTap={{ scale: 0.96 }}
                  onClick={shareWhatsApp}
                  style={{
                    background: "#25D366",
                    color: "#FFFFFF",
                    border: "none",
                    borderRadius: "999px",
                    padding: "12px 28px",
                    fontFamily: "'Outfit', sans-serif",
                    fontSize: "14px",
                    cursor: "pointer"
                  }}
                >
                  Share on WhatsApp
                </motion.button>
              </div>

              <div style={{ marginTop: "24px", display: "flex", gap: "8px", justifyContent: "center" }}>
                <input 
                  type="email"
                  value={partnerEmail}
                  onChange={(e) => setPartnerEmail(e.target.value)}
                  placeholder="Or invite by email address..."
                  style={{
                    flex: 1,
                    height: "44px",
                    borderRadius: "12px",
                    border: "1px solid #D4CEC4",
                    background: "#FFFFFF",
                    fontFamily: "'Outfit', sans-serif",
                    fontSize: "14px",
                    color: "#1A1A1A",
                    padding: "0 16px",
                    outline: "none"
                  }}
                />
                <button
                  onClick={sendEmailInvite}
                  disabled={!partnerEmail || isSendingInvite}
                  style={{
                    height: "44px",
                    padding: "0 16px",
                    borderRadius: "12px",
                    background: "#1A1A1A",
                    fontFamily: "'Outfit', sans-serif",
                    fontSize: "14px",
                    color: "#FFFFFF",
                    border: "none",
                    cursor: (!partnerEmail || isSendingInvite) ? "default" : "pointer",
                    opacity: (!partnerEmail || isSendingInvite) ? 0.5 : 1
                  }}
                >
                  {isSendingInvite ? '...' : inviteSent ? 'Sent!' : 'Send'}
                </button>
              </div>
            </motion.div>
          )}

          {selectedMode === "join" && (
            <motion.div
              key="join-ui"
              initial={{ opacity: 0, y: 24, filter: "blur(4px)" }}
              animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
              exit={{ opacity: 0, y: -16 }}
              transition={spring}
              style={{ marginTop: "24px" }}
            >
              <p style={{
                fontFamily: "'Outfit', sans-serif",
                fontSize: "14px",
                color: "#6B6560",
                margin: "0 0 16px"
              }}>
                Enter the 6-digit code
              </p>
              <motion.div 
                animate={isShaking ? { x: [0, -8, 8, -6, 6, 0] } : {}}
                transition={{ duration: 0.4 }}
                style={{ display: "flex", gap: "10px", justifyContent: "center" }}
              >
                {[0, 1, 2, 3, 4, 5].map(i => (
                  <input
                    key={i}
                    ref={el => { inputRefs.current[i] = el; }}
                    maxLength={1}
                    inputMode="numeric"
                    value={joinCode[i]}
                    onChange={e => handleJoinCodeChange(i, e.target.value)}
                    onKeyDown={e => handleKeyDown(i, e)}
                    style={{
                      width: "44px",
                      height: "56px",
                      textAlign: "center",
                      fontFamily: "'Fraunces', serif",
                      fontSize: "24px",
                      color: "#1A1A1A",
                      background: "#EDE8DF",
                      border: "1px solid #D4CEC4",
                      borderRadius: "12px",
                      outline: "none",
                      caretColor: "#B8955A"
                    }}
                  />
                ))}
              </motion.div>
              {error && (
                <motion.p
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  style={{
                    color: "#C97B6A",
                    fontSize: "14px",
                    fontFamily: "'Outfit', sans-serif",
                    textAlign: "center",
                    marginTop: "16px"
                  }}
                >
                  {error}
                </motion.p>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Bottom section — progress dots + button */}
      <div style={{ display: "flex", flexDirection: "column", gap: "32px" }}>
        {/* Progress dots — 4 total, third one active */}
        <div style={{ display: "flex", gap: "8px" }}>
          {[0, 1, 2, 3].map(i => (
            <motion.div
              key={i}
              animate={{
                width: i === 2 ? "24px" : "8px",
                background: i === 2 ? "#B8955A" : "#D4CEC4"
              }}
              style={{ height: "8px", borderRadius: "999px" }}
              transition={{ type: "spring", stiffness: 300, damping: 24 }}
            />
          ))}
        </div>

        {/* Continue button */}
        <AnimatePresence>
          {selectedMode && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 20 }}
            >
              {selectedMode === "create" ? (
                <motion.button
                  disabled
                  animate={{ opacity: [0.5, 1, 0.5] }}
                  transition={{ repeat: Infinity, duration: 2 }}
                  style={{
                    width: "100%",
                    height: "56px",
                    background: "#1A1A1A",
                    border: "none",
                    borderRadius: "999px",
                    fontFamily: "'Outfit', sans-serif",
                    fontSize: "16px",
                    fontWeight: 500,
                    color: "#FFFFFF",
                    cursor: "default"
                  }}
                >
                  Waiting for partner...
                </motion.button>
              ) : (
                <motion.button
                  whileTap={{ scale: 0.96 }}
                  whileHover={joinCode.every(d => d !== "") ? { scale: 1.02 } : {}}
                  onClick={handleJoin}
                  disabled={isJoining || !joinCode.every(d => d !== "")}
                  style={{
                    width: "100%",
                    height: "56px",
                    background: joinCode.every(d => d !== "") ? "#1A1A1A" : "#D4CEC4",
                    border: "none",
                    borderRadius: "999px",
                    fontFamily: "'Outfit', sans-serif",
                    fontSize: "16px",
                    fontWeight: 500,
                    color: "#FFFFFF",
                    cursor: joinCode.every(d => d !== "") ? "pointer" : "default",
                    boxShadow: "0 8px 32px rgba(26,26,26,0.15)"
                  }}
                >
                  {isJoining ? "Joining..." : "Join household"}
                </motion.button>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
}

import { useEffect, useState } from "react";
import { motion } from "motion/react";
import confetti from "canvas-confetti";
import { doc, getDoc, collection, query, where, getDocs } from "firebase/firestore";
import { db, auth } from "../../firebase";
import { useAuth } from "../AuthWrapper";

interface OnboardingStep4Props {
  onComplete: () => void;
}

const spring = { type: "spring" as const, stiffness: 280, damping: 22 };

const fadeUp = (delay = 0) => ({
  initial: { opacity: 0, y: 48, filter: "blur(4px)" },
  animate: { opacity: 1, y: 0, filter: "blur(0px)" },
  transition: { ...spring, delay }
});

export default function OnboardingStep4({ onComplete }: OnboardingStep4Props) {
  const { user } = useAuth();
  const [partnerUser, setPartnerUser] = useState<{ photoURL: string; displayName: string } | null>(null);
  const [currentUserProfile, setCurrentUserProfile] = useState<{ photoURL: string; displayName: string } | null>(null);

  useEffect(() => {
    // Fetch user profiles
    const fetchProfiles = async () => {
      if (!user) return;

      try {
        const userDoc = await getDoc(doc(db, "users", user.uid));
        if (userDoc.exists()) {
          const userData = userDoc.data();
          setCurrentUserProfile({
            photoURL: userData.photoURL || user.photoURL || `https://ui-avatars.com/api/?name=${userData.displayName || 'Me'}&background=B8955A&color=fff`,
            displayName: userData.displayName || "Me"
          });

          const householdId = userData.householdId;
          if (householdId) {
            const q = query(
              collection(db, "users"),
              where("householdId", "==", householdId),
              where("uid", "!=", user.uid)
            );
            const querySnapshot = await getDocs(q);
            if (!querySnapshot.empty) {
              const pData = querySnapshot.docs[0].data();
              setPartnerUser({
                photoURL: pData.photoURL || `https://ui-avatars.com/api/?name=${pData.displayName || 'Partner'}&background=D4CEC4&color=1A1A1A`,
                displayName: pData.displayName || "Partner"
              });
            }
          }
        }
      } catch (err) {
        console.error("Error fetching profiles:", err);
      }
    };

    fetchProfiles();

    // Fire confetti burst after 400ms
    const timer = setTimeout(() => {
      confetti({
        particleCount: 80,
        spread: 70,
        origin: { y: 0.5 },
        colors: ["#B8955A", "#F0E4CC", "#1A1A1A", "#EDE8DF"],
        gravity: 0.8,
        scalar: 0.9
      });
    }, 400);

    return () => clearTimeout(timer);
  }, [user]);

  const goToDashboard = () => {
    // Clear onboarding flow from history and navigate
    onComplete();
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: "100%" }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, scale: 0.96 }}
      transition={{ type: "spring", stiffness: 280, damping: 26 }}
      style={{
        minHeight: "100dvh",
        background: "#F8F4EE",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: "60px 32px",
        textAlign: "center"
      }}
    >
      {/* Celebration icon instead of Lottie */}
      <motion.div {...fadeUp(0)} style={{ width: "200px", height: "100px", margin: "0 auto 32px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "64px" }}>
        ✨
      </motion.div>

      {/* Text content */}
      <motion.p {...fadeUp(0.1)} style={{
        fontFamily: "'Outfit', sans-serif",
        fontSize: "13px",
        letterSpacing: "2px",
        textTransform: "uppercase",
        color: "#B8955A",
        margin: "0 0 16px"
      }}>
        You're all set
      </motion.p>

      <motion.h1 {...fadeUp(0.2)} style={{
        fontFamily: "'Fraunces', serif",
        fontSize: "clamp(36px, 10vw, 52px)",
        fontWeight: 300,
        lineHeight: 1.1,
        color: "#1A1A1A",
        margin: "0 0 16px",
        letterSpacing: "-1.5px"
      }}>
        Your space<br/>is ready
      </motion.h1>

      <motion.p {...fadeUp(0.3)} style={{
        fontFamily: "'Outfit', sans-serif",
        fontSize: "16px",
        color: "#6B6560",
        margin: "0 0 56px",
        lineHeight: 1.6,
        maxWidth: "260px"
      }}>
        Everything is set up and waiting for you both.
      </motion.p>

      {/* Two partner avatars side by side */}
      <motion.div
        {...fadeUp(0.35)}
        style={{
          display: "flex",
          alignItems: "center",
          gap: "0px",
          margin: "0 auto 48px",
          position: "relative",
          width: "fit-content"
        }}
      >
        {/* Your avatar */}
        <img
          src={currentUserProfile?.photoURL || user?.photoURL || ""}
          referrerPolicy="no-referrer"
          style={{
            width: "56px",
            height: "56px",
            borderRadius: "50%",
            border: "3px solid #F8F4EE",
            position: "relative",
            zIndex: 2,
            objectFit: "cover"
          }}
        />
        {/* Brass link dot between avatars */}
        <div style={{
          width: "12px",
          height: "12px",
          borderRadius: "50%",
          background: "#B8955A",
          margin: "0 -2px",
          zIndex: 3,
          position: "relative"
        }} />
        {/* Partner avatar */}
        <img
          src={partnerUser?.photoURL || `https://ui-avatars.com/api/?name=Partner&background=D4CEC4&color=1A1A1A`}
          referrerPolicy="no-referrer"
          style={{
            width: "56px",
            height: "56px",
            borderRadius: "50%",
            border: "3px solid #F8F4EE",
            position: "relative",
            zIndex: 2,
            objectFit: "cover"
          }}
        />
      </motion.div>

      {/* Open OurSpace button */}
      <motion.button
        {...fadeUp(0.45)}
        whileTap={{ scale: 0.96 }}
