        }}
      >
        Open OurSpace ✦
      </motion.button>

      {/* Progress dots — all 4 active in brass */}
      <motion.div {...fadeUp(0.5)} style={{ display: "flex", gap: "8px", marginTop: "40px" }}>
        {[0, 1, 2, 3].map(i => (
          <motion.div
            key={i}
            initial={{ width: "8px", background: "#D4CEC4" }}
            animate={{ width: "24px", background: "#B8955A" }}
