import { useEffect, useRef, useState } from "react";
import gsap from "gsap";

interface LaunchScreenProps {
  onComplete: () => void;
  isAnniversary?: boolean;
}

export default function LaunchScreen({ onComplete, isAnniversary = false }: LaunchScreenProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const textRef = useRef<HTMLHeadingElement>(null);
  const dotRef = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    const tl = gsap.timeline({
      onComplete: () => {
        gsap.to(containerRef.current, {
          opacity: 0,
          duration: 0.4,
          ease: "power2.inOut",
          onComplete
        });
      }
    });

    if (isAnniversary) {
      // Longer timeline for anniversary
      tl.fromTo(textRef.current, 
        { opacity: 0, y: 24 },
        { opacity: 1, y: 0, duration: 0.8, ease: "power3.out" }
      )
      .to({}, { duration: 2.5 }); // Hold
    } else {
      tl.fromTo(textRef.current, 
        { opacity: 0, y: 24 },
        { opacity: 1, y: 0, duration: 0.8, ease: "power3.out" }
      )
      .fromTo(dotRef.current,
        { opacity: 0, scale: 0 },
        { opacity: 1, scale: 1, duration: 0.6, ease: "back.out(2)" },
        "-=0.3"
      )
      .to({}, { duration: 1.1 }); // Hold for 1.1s (Total ~2.5s)
    }

    return () => { tl.kill(); };
  }, [onComplete, isAnniversary]);

  return (
    <div ref={containerRef} className="fixed inset-0 z-50 flex flex-col items-center justify-center bg-linen">
      {isAnniversary && (
        <div className="mb-8 h-48 w-48 flex items-center justify-center text-6xl animate-bounce">
          ❤️
        </div>
      )}
      <h1 ref={textRef} className="flex items-baseline font-serif text-[48px] font-light text-charcoal">
        {isAnniversary ? "Happy Anniversary" : "OurSpace"}
        {!isAnniversary && (
          <span ref={dotRef} className="ml-1.5 inline-block h-3 w-3 rounded-full bg-brass" />
        )}
      </h1>
    </div>
  );
}

import { useEffect, useState } from "react";
import { motion } from "motion/react";
import { Leaf, Sun, Image as ImageIcon, Coins, Globe2 } from "lucide-react";

interface LottieEmptyStateProps {
  message: string;
  fallbackIcon: "plant" | "sun" | "polaroid" | "coins" | "globe";
}

export default function LottieEmptyState({ message, fallbackIcon }: LottieEmptyStateProps) {
  const renderFallback = () => {
    switch (fallbackIcon) {
      case "plant":
        return (
          <motion.div animate={{ scale: [0.9, 1.05, 0.9] }} transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}>
            <Leaf className="h-16 w-16 text-brass/40" strokeWidth={1.5} />
          </motion.div>
        );
      case "sun":
        return (
          <motion.div animate={{ rotate: 360 }} transition={{ duration: 20, repeat: Infinity, ease: "linear" }}>
            <Sun className="h-16 w-16 text-brass/40" strokeWidth={1.5} />
          </motion.div>
        );
      case "polaroid":
        return (
          <motion.div animate={{ y: [-5, 5, -5], rotate: [-2, 2, -2] }} transition={{ duration: 5, repeat: Infinity, ease: "easeInOut" }}>
            <ImageIcon className="h-16 w-16 text-brass/40" strokeWidth={1.5} />
          </motion.div>
        );
      case "coins":
        return (
          <motion.div animate={{ y: [0, -8, 0] }} transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}>
            <Coins className="h-16 w-16 text-brass/40" strokeWidth={1.5} />
          </motion.div>
        );
      case "globe":
        return (
          <motion.div animate={{ rotate: 360 }} transition={{ duration: 15, repeat: Infinity, ease: "linear" }}>
            <Globe2 className="h-16 w-16 text-brass/40" strokeWidth={1.5} />
          </motion.div>
        );
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6, ease: "easeOut" }}
      className="flex flex-col items-center justify-center p-8 text-center"
    >
      <div className="flex h-[120px] w-[120px] items-center justify-center opacity-90">
        {renderFallback()}
      </div>
      <p className="mt-4 font-sans text-[15px] text-warm-grey">{message}</p>
    </motion.div>
  );
}

import { useState, useRef, useEffect } from "react";
import { motion, useAnimation } from "motion/react";
import { useDrag } from "@use-gesture/react";
import { springs } from "../../lib/motion";
import LottieSpinner from "./LottieSpinner";

interface PullToRefreshProps {
  onRefresh: () => Promise<void>;
  children: React.ReactNode;
}

export default function PullToRefresh({ onRefresh, children }: PullToRefreshProps) {
  const [isRefreshing, setIsRefreshing] = useState(false);
  const controls = useAnimation();
  const containerRef = useRef<HTMLDivElement>(null);
  const maxPull = 120;
  const threshold = 80;

  const bind = useDrag(({ down, movement: [, my], cancel }) => {
    // Only allow pull to refresh if we are at the top of the container
    if (containerRef.current && containerRef.current.scrollTop > 0) {
      return;
    }

    if (isRefreshing) return;

    if (down) {
      // Rubber band effect
      const pullDistance = my > 0 ? Math.min(my * 0.4, maxPull) : 0;
      controls.set({ y: pullDistance });
    } else {
      if (my > threshold) {
        setIsRefreshing(true);
        controls.start({ y: 50, transition: springs.snappy });
        onRefresh().then(() => {
          setIsRefreshing(false);
          controls.start({ y: 0, transition: springs.bouncy });
        });
      } else {
        controls.start({ y: 0, transition: springs.bouncy });
      }
    }
  }, { axis: 'y' });

  const bindProps = bind() as Record<string, unknown>;

  return (
    <div ref={containerRef} className="h-full w-full overflow-y-auto overflow-x-hidden touch-pan-y" {...bindProps}>
      <div className="absolute left-0 right-0 top-0 flex justify-center pt-4">
        {isRefreshing && (
          <motion.div
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0, opacity: 0 }}
          >
            <LottieSpinner />
          </motion.div>
        )}
      </div>
      <motion.div animate={controls} className="min-h-full w-full">
        {children}
      </motion.div>
    </div>
  );
}

import { useState } from "react";
import { motion, AnimatePresence } from "motion/react";
import { useDrag } from "@use-gesture/react";
import { springs } from "../../lib/motion";
import { Check, Trash2 } from "lucide-react";
import { triggerBrassBurst } from "../../lib/confetti";

interface SwipeableItemProps {
  children: React.ReactNode;
  onComplete?: () => void;
  onDelete?: () => void;
  removeOnComplete?: boolean;
  removeOnDelete?: boolean;
}

export default function SwipeableItem({ 
  children, 
  onComplete, 
  onDelete, 
  removeOnComplete = true, 
  removeOnDelete = true 
}: SwipeableItemProps) {
  const [x, setX] = useState(0);
  const [isRemoved, setIsRemoved] = useState(false);
  const threshold = 80;

  const bind = useDrag(({ down, movement: [mx], velocity: [vx], direction: [dx], event }) => {
    if (isRemoved) return;

    if (down) {
      setX(mx);
    } else {
      if (mx > threshold || (vx > 0.5 && dx > 0)) {
        // Complete
        if (removeOnComplete) {
          setX(window.innerWidth);
          setIsRemoved(true);
        } else {
          setX(0);
        }
        if (event && 'clientX' in event && 'clientY' in event) {
          triggerBrassBurst((event as MouseEvent).clientX, (event as MouseEvent).clientY);
        } else {
          triggerBrassBurst(window.innerWidth / 2, window.innerHeight / 2);
        }
        setTimeout(() => { if (onComplete) onComplete(); }, removeOnComplete ? 300 : 0);
      } else if (mx < -threshold || (vx > 0.5 && dx < 0)) {
        // Delete
        if (removeOnDelete) {
          setX(-window.innerWidth);
          setIsRemoved(true);
        } else {
          setX(0);
        }
        setTimeout(() => { if (onDelete) onDelete(); }, removeOnDelete ? 300 : 0);
      } else {
        // Reset
        setX(0);
      }
    }
  });

  // @ts-ignore
  const bindProps = (bind as any)() as Record<string, unknown>;

  return (
    <AnimatePresence>
      {!isRemoved && (
        <motion.div 
          layout
          initial={{ opacity: 1, height: "auto" }}
          exit={{ opacity: 0, height: 0, marginBottom: 0, transition: springs.soft }}
          className="relative w-full overflow-hidden rounded-2xl mb-3"
        >
          {/* Background actions */}
          <div className="absolute inset-0 flex items-center justify-between overflow-hidden">
            {/* Green wash (Complete) */}
            <motion.div 
              className="absolute inset-y-0 left-0 bg-green-100 flex items-center pl-6"
              style={{ 
                width: x > 0 ? x + 100 : 0,
                opacity: x > 0 ? Math.min(x / threshold, 1) : 0
              }}
            >
              <div className="flex h-10 w-10 items-center justify-center rounded-full bg-green-200 text-green-600">
                <Check size={20} />
              </div>
            </motion.div>

            {/* Red wash (Delete) */}
            <motion.div 
              className="absolute inset-y-0 right-0 bg-red-100 flex items-center justify-end pr-6"
              style={{ 
                width: x < 0 ? Math.abs(x) + 100 : 0,
                opacity: x < 0 ? Math.min(Math.abs(x) / threshold, 1) : 0
              }}
            >
              <div className="flex h-10 w-10 items-center justify-center rounded-full bg-red-200 text-red-600">
                <Trash2 size={20} />
              </div>
            </motion.div>
          </div>

          {/* Foreground item */}
          <motion.div
            {...bindProps}
            animate={{ x }}
            transition={x === 0 ? springs.bouncy : { type: "tween", duration: 0.2 }}
            className="relative z-10 touch-pan-y"
            style={{ x }}
          >
            {children}
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

/**
 * OurSpace — Bank Statement Parsers
 * Supports CommBank, NAB, ANZ, Westpac, Macquarie, ING, Bendigo, generic
 * CSV parsing is pure TS. PDF uses Gemini Vision.
 */

import { GoogleGenerativeAI } from '@google/generative-ai';
import { detectIncomeType } from './cashflow';

// ============================================================
// TYPES
// ============================================================
export interface BankTransaction {
  id: string;
  date: Date;
  description: string;
  cleanDescription: string;
  amount: number;         // negative = expense, positive = income
  balance?: number;
  type: 'debit' | 'credit';
  incomeType?: 'salary' | 'refund' | 'transfer' | 'interest' | 'other_income';
  bankSource: string;
  rawRow: string;
}

export type BankFormat = 'commbank' | 'nab' | 'anz' | 'westpac' | 'macquarie' | 'ing' | 'bendigo' | 'stgeorge' | 'generic';

// ============================================================
// BANK AUTO-DETECTION
// ============================================================
export const detectBank = (filename: string, firstLines: string): BankFormat => {
  const fn = filename.toLowerCase();
  const fl = firstLines.toLowerCase();

  if (fn.includes('commbank') || fl.includes('commonwealth bank') || fl.includes('netbank')) return 'commbank';
  if (fn.includes('nab') || fl.includes('national australia bank') || fl.includes('nab bank')) return 'nab';
  if (fn.includes('anz') || fl.includes('anz bank') || fl.includes('anz account')) return 'anz';
  if (fn.includes('westpac') || fl.includes('westpac')) return 'westpac';
  if (fn.includes('macquarie') || fl.includes('macquarie bank')) return 'macquarie';
  if (fn.includes('ing') || fl.includes('ing bank') || fl.includes('ing direct')) return 'ing';
  if (fn.includes('bendigo') || fl.includes('bendigo bank')) return 'bendigo';
  if (fn.includes('stgeorge') || fn.includes('st george') || fl.includes('st.george')) return 'stgeorge';
  return 'generic';
};

// ============================================================
// DESCRIPTION CLEANER
// ============================================================
const cleanDesc = (raw: string): string => {
  return raw
    .replace(/eftpos|pos purchase|pos debit|visa purchase|visa debit|eftpos purchase/gi, '')
    .replace(/card \d{4,}/gi, '')       // remove card numbers
    .replace(/\d{6,}/g, '')             // remove long reference numbers
    .replace(/value date:?\s*\d{2}\/\d{2}\/\d{4}/gi, '')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/^[^a-zA-Z]+/, '');        // remove leading non-alpha
};

// ============================================================
// PARSE DATE — handles DD/MM/YYYY, YYYY-MM-DD, "01 Apr 2026", etc.
// ============================================================
const parseDate = (str: string): Date => {
  if (!str) return new Date();

  // YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}/.test(str)) return new Date(str);

  // DD/MM/YYYY
  if (/^\d{2}\/\d{2}\/\d{4}/.test(str)) {
    const [d, m, y] = str.split('/').map(Number);
    return new Date(y, m - 1, d);
  }

  // "01 Apr 2026"
  const match = str.match(/^(\d{1,2})\s+([A-Za-z]{3})\s+(\d{4})/);
  if (match) {
    return new Date(`${match[2]} ${match[1]}, ${match[3]}`);
  }

  return new Date(str);
};

// ============================================================
// PARSE AMOUNT — handles negative, parentheses, commas
// ============================================================
const parseAmount = (str: string, isDebit?: boolean): number => {
  if (!str) return 0;
  const negative = str.includes('−') || str.includes('-') || str.startsWith('(');
  const cleaned  = str.replace(/[^0-9.]/g, '');
  const value    = parseFloat(cleaned) || 0;
  if (isDebit) return -value;
  return negative ? -value : value;
};

// ============================================================
// COMMBANK CSV
// Format: Date,Amount,Description,Balance
// ============================================================
const parseCommBank = (csv: string): BankTransaction[] => {
  const lines = csv.split('\n').filter(l => l.trim() && !l.startsWith('"Date"'));
  return lines.map((line, i) => {
    const cols = parseCSVLine(line);
    const amount     = parseAmount(cols[1] || '0');
    const type: 'debit' | 'credit' = amount < 0 ? 'debit' : 'credit';
    const desc       = cols[2] || '';
    const clean      = cleanDesc(desc);
    const tx: BankTransaction = {
      id: `cb-${i}`,
      date: parseDate(cols[0] || ''),
      description: desc,
      cleanDescription: clean,
      amount,
      balance: parseAmount(cols[3] || '0'),
      type,
      bankSource: 'commbank',
      rawRow: line,
    };
    if (type === 'credit') tx.incomeType = detectIncomeType(desc);
    return tx;
  }).filter(t => !isNaN(t.amount));
};

// ============================================================
// NAB CSV
// Format: Date,Amount,Description,Merchant Name,Category
// ============================================================
const parseNAB = (csv: string): BankTransaction[] => {
  const lines = csv.split('\n').filter(l => l.trim() && !l.toLowerCase().startsWith('date'));
  return lines.map((line, i) => {
    const cols    = parseCSVLine(line);
    const amount  = parseAmount(cols[1] || '0');
    const type: 'debit' | 'credit' = amount < 0 ? 'debit' : 'credit';
    const desc    = cols[2] || '';
    const tx: BankTransaction = {
      id: `nab-${i}`,
      date: parseDate(cols[0] || ''),
      description: desc,
      cleanDescription: cleanDesc(desc),
      amount,
      type,
      bankSource: 'nab',
      rawRow: line,
    };
    if (type === 'credit') tx.incomeType = detectIncomeType(desc);
    return tx;
  }).filter(t => !isNaN(t.amount));
};

// ============================================================
// ANZ CSV
// Format: Details,Particulars,Code,Reference,Amount,Date,...
// ============================================================
const parseANZ = (csv: string): BankTransaction[] => {
  const lines = csv.split('\n').filter(l => l.trim() && !l.toLowerCase().startsWith('details'));
  return lines.map((line, i) => {
    const cols   = parseCSVLine(line);
    const amount = parseAmount(cols[4] || '0');
    const type: 'debit' | 'credit' = amount < 0 ? 'debit' : 'credit';
    const desc   = [cols[0], cols[1]].filter(Boolean).join(' ').trim();
    const tx: BankTransaction = {
      id: `anz-${i}`,
      date: parseDate(cols[5] || ''),
      description: desc,
      cleanDescription: cleanDesc(desc),
      amount,
      type,
      bankSource: 'anz',
      rawRow: line,
    };
    if (type === 'credit') tx.incomeType = detectIncomeType(desc);
    return tx;
  }).filter(t => !isNaN(t.amount));
};

// ============================================================
// WESTPAC CSV
// Format: "BSB","Account Number","Transaction Date","Narration","Cheque","Debit","Credit","Balance"
// ============================================================
const parseWestpac = (csv: string): BankTransaction[] => {
  const lines = csv.split('\n').filter(l => l.trim() && !l.toLowerCase().startsWith('"bsb"'));
  return lines.map((line, i) => {
    const cols = parseCSVLine(line);
    const debit  = parseAmount(cols[5] || '0');
    const credit = parseAmount(cols[6] || '0');
    const amount = credit > 0 ? credit : -debit;
    const type: 'debit' | 'credit' = amount < 0 ? 'debit' : 'credit';
    const desc = cols[3] || '';
    const tx: BankTransaction = {
      id: `wp-${i}`,
      date: parseDate(cols[2] || ''),
      description: desc,
      cleanDescription: cleanDesc(desc),
      amount,
      balance: parseAmount(cols[7] || '0'),
      type,
      bankSource: 'westpac',
      rawRow: line,
    };
    if (type === 'credit') tx.incomeType = detectIncomeType(desc);
    return tx;
  }).filter(t => !isNaN(t.amount));
};

// ============================================================
// GENERIC CSV PARSER — column detection fallback
// ============================================================
const parseGenericCSV = (csv: string): BankTransaction[] => {
  const lines = csv.split('\n').filter(l => l.trim());
  if (lines.length < 2) return [];

  const header = lines[0].toLowerCase();
  const isDateFirst   = /^"?date/i.test(header);
  const hasDebitCredit = /debit.+credit|credit.+debit/i.test(header);

  return lines.slice(1).map((line, i) => {
    const cols = parseCSVLine(line);
    let date: Date = new Date(), amount = 0, desc = '';

    if (hasDebitCredit) {
      date   = parseDate(cols[0] || '');
      desc   = cols[1] || cols[2] || '';
      const debit  = parseAmount(cols[3] || '0');
      const credit = parseAmount(cols[4] || '0');
      amount = credit > 0 ? credit : -debit;
    } else if (isDateFirst) {
      date   = parseDate(cols[0] || '');
      amount = parseAmount(cols[1] || '0');
      desc   = cols[2] || '';
    } else {
      // last resort: find columns by pattern
      for (const col of cols) {
        if (/\d{1,2}\/\d{1,2}\/\d{4}|\d{4}-\d{2}-\d{2}/.test(col)) { date = parseDate(col); continue; }
        if (/^-?\d+\.\d+$/.test(col.replace(/[$,]/g, '')))           { amount = parseAmount(col); continue; }
        if (col.length > 3 && !/^\d/.test(col))                      { desc = col; }
      }
    }

    const type: 'debit' | 'credit' = amount < 0 ? 'debit' : 'credit';
    const tx: BankTransaction = {
      id: `generic-${i}`,
      date,
      description: desc,
      cleanDescription: cleanDesc(desc),
      amount,
      type,
      bankSource: 'generic',
      rawRow: line,
    };
    if (type === 'credit') tx.incomeType = detectIncomeType(desc);
    return tx;
  }).filter(t => !isNaN(t.amount) && t.amount !== 0);
};

// ============================================================
// CSV LINE PARSER (handles quoted fields)
// ============================================================
const parseCSVLine = (line: string): string[] => {
  const result: string[] = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim().replace(/^"|"$/g, ''));
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim().replace(/^"|"$/g, ''));
  return result;
};

// ============================================================
// MAIN CSV PARSER — dispatches to bank-specific parser
// ============================================================
export const parseCSV = (csv: string, filename: string): BankTransaction[] => {
  const firstLines = csv.split('\n').slice(0, 3).join('\n');
  const bank = detectBank(filename, firstLines);

  try {
    switch (bank) {
      case 'commbank': return parseCommBank(csv);
      case 'nab':      return parseNAB(csv);
      case 'anz':      return parseANZ(csv);
      case 'westpac':  return parseWestpac(csv);
      default:         return parseGenericCSV(csv);
    }
  } catch (e) {
    console.warn(`${bank} parser failed, trying generic:`, e);
    return parseGenericCSV(csv);
  }
};

// ============================================================
// PDF PARSER — Gemini Vision
// ============================================================
export const parsePDF = async (
  file: File
): Promise<BankTransaction[]> => {
  const apiKey = (import.meta as any).env?.VITE_GEMINI_API_KEY;
  if (!apiKey) throw new Error('Bank parsing requires VITE_GEMINI_API_KEY');

  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({ model: 'gemini-flash-latest' });
  const arrayBuffer = await file.arrayBuffer();
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  bytes.forEach(b => binary += String.fromCharCode(b));
  const base64 = btoa(binary);

  const result = await model.generateContent([
    {
      inlineData: {
        mimeType: 'application/pdf',
        data: base64,
      },
    },
    `Extract ALL bank transactions from this statement. Return ONLY a JSON array, no markdown:
[{
  "date": "YYYY-MM-DD",
  "description": "string",
  "amount": -45.50,
  "balance": 1234.56,
  "type": "debit"
}]
Rules:
- amount MUST be negative for expenses/debits, positive for income/credits
- Include every transaction visible — no summary rows
- date must be ISO format YYYY-MM-DD
- If balance not visible use null`,
  ]);

  const text = result.response.text().trim();
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed: Array<{ date: string; description: string; amount: number; balance?: number; type: 'debit' | 'credit' }> = JSON.parse(cleaned);

  return parsed.map((tx, i) => {
    const type: 'debit' | 'credit' = tx.amount < 0 ? 'debit' : 'credit';
    const t: BankTransaction = {
      id: `pdf-${i}`,
      date: parseDate(tx.date),
      description: tx.description,
      cleanDescription: cleanDesc(tx.description),
      amount: tx.amount,
      balance: tx.balance,
      type,
      bankSource: `pdf-${file.name}`,
      rawRow: JSON.stringify(tx),
    };
    if (type === 'credit') t.incomeType = detectIncomeType(tx.description);
    return t;
  });
};

// ============================================================
// DUPLICATE DETECTION
// ============================================================
export interface DuplicateCheck {
  isDuplicate: boolean;
  matchedExpenseId?: string;
  matchedMerchant?: string;
}

const levenshtein = (a: string, b: string): number => {
  const dp = Array.from({ length: a.length + 1 }, (_, i) =>
    Array.from({ length: b.length + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
  );
  for (let i = 1; i <= a.length; i++) {
    for (let j = 1; j <= b.length; j++) {
      dp[i][j] = a[i-1] === b[j-1]
        ? dp[i-1][j-1]
        : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
    }
  }
  return dp[a.length][b.length];
};

export const checkDuplicate = (
  tx: BankTransaction,
  existingExpenses: Array<{ id: string; merchantName: string; total: number; date: Date }>
): DuplicateCheck => {
  const txAbs = Math.abs(tx.amount);
  const txDate = tx.date;

  for (const exp of existingExpenses) {
    // Amount within $0.10
    if (Math.abs(Math.abs(exp.total) - txAbs) > 0.10) continue;

    // Date within 2 days
    const daysDiff = Math.abs(txDate.getTime() - exp.date.getTime()) / (1000 * 60 * 60 * 24);
    if (daysDiff > 2) continue;

    // Merchant name fuzzy match
    const dist = levenshtein(
      tx.cleanDescription.toLowerCase().substring(0, 20),
      exp.merchantName.toLowerCase().substring(0, 20)
    );
    if (dist <= 4) {
      return { isDuplicate: true, matchedExpenseId: exp.id, matchedMerchant: exp.merchantName };
    }
  }

  return { isDuplicate: false };
};

// ============================================================
// SUBSCRIPTION DETECTION from recurring transactions
// ============================================================
export interface DetectedSubscription {
  merchantName: string;
  amount: number;
  intervalDays: number;
  frequency: 'monthly' | 'yearly' | 'weekly' | 'unknown';
  nextEstimatedDate: Date;
  occurrences: number;
}

export const detectSubscriptions = (transactions: BankTransaction[]): DetectedSubscription[] => {
  // Group debits by clean merchant name
  const merchantGroups = new Map<string, BankTransaction[]>();

  for (const tx of transactions) {
    if (tx.type !== 'debit') continue;
    const key = tx.cleanDescription.toLowerCase().substring(0, 30);
    if (!merchantGroups.has(key)) merchantGroups.set(key, []);
    merchantGroups.get(key)!.push(tx);
  }

  const subscriptions: DetectedSubscription[] = [];

  for (const [name, txs] of merchantGroups) {
    if (txs.length < 2) continue;

    // Sort by date
    txs.sort((a, b) => a.date.getTime() - b.date.getTime());

    // Calculate average interval
    const intervals: number[] = [];
    for (let i = 1; i < txs.length; i++) {
      const days = (txs[i].date.getTime() - txs[i-1].date.getTime()) / (1000 * 60 * 60 * 24);
      intervals.push(days);
    }
    const avgInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;

    // Check consistency (within 5 days variance)
    const isConsistent = intervals.every(d => Math.abs(d - avgInterval) < 5);
    if (!isConsistent && txs.length < 4) continue;

    // Determine frequency
    let frequency: DetectedSubscription['frequency'] = 'unknown';
    if (avgInterval >= 25 && avgInterval <= 35)    frequency = 'monthly';
    else if (avgInterval >= 350 && avgInterval <= 380) frequency = 'yearly';
    else if (avgInterval >= 5 && avgInterval <= 9) frequency = 'weekly';

    if (frequency === 'unknown' && txs.length < 3) continue;

    // Average amount
    const avgAmount = Math.abs(txs.reduce((a, tx) => a + tx.amount, 0) / txs.length);
    const amountsConsistent = txs.every(tx => Math.abs(Math.abs(tx.amount) - avgAmount) < 2);
    if (!amountsConsistent && txs.length < 4) continue;

    // Estimate next charge
    const lastDate = txs[txs.length - 1].date;
    const nextDate = new Date(lastDate.getTime() + avgInterval * 24 * 60 * 60 * 1000);

    subscriptions.push({
      merchantName: txs[0].cleanDescription || name,
      amount: avgAmount,
      intervalDays: Math.round(avgInterval),
      frequency,
      nextEstimatedDate: nextDate,
      occurrences: txs.length,
    });
  }

  return subscriptions.sort((a, b) => b.amount - a.amount);
};

/**
 * OurSpace — Cash Flow Engine + ML Forecasting
 * Pure JS linear regression. No external libraries.
 */

// ============================================================
// LINEAR REGRESSION
// ============================================================
export interface RegressionResult {
  slope: number;
  intercept: number;
  r2: number; // coefficient of determination (0-1)
}

export const linearRegression = (x: number[], y: number[]): RegressionResult => {
  const n = x.length;
  if (n < 2) return { slope: 0, intercept: y[0] || 0, r2: 0 };

  const sumX  = x.reduce((a, b) => a + b, 0);
  const sumY  = y.reduce((a, b) => a + b, 0);
  const sumXY = x.reduce((sum, xi, i) => sum + xi * y[i], 0);
  const sumXX = x.reduce((sum, xi) => sum + xi * xi, 0);
  const sumYY = y.reduce((sum, yi) => sum + yi * yi, 0);

  const denom = n * sumXX - sumX * sumX;
  if (denom === 0) return { slope: 0, intercept: sumY / n, r2: 0 };

  const slope     = (n * sumXY - sumX * sumY) / denom;
  const intercept = (sumY - slope * sumX) / n;

  // R² calculation
  const meanY = sumY / n;
  const ssTot = y.reduce((sum, yi) => sum + Math.pow(yi - meanY, 2), 0);
  const ssRes = y.reduce((sum, yi, i) => sum + Math.pow(yi - (slope * x[i] + intercept), 2), 0);
  const r2 = ssTot === 0 ? 1 : 1 - ssRes / ssTot;

  return { slope, intercept, r2: Math.max(0, r2) };
};

export const predict = (reg: RegressionResult, month: number): number => {
  return Math.max(0, reg.slope * month + reg.intercept);
};

// ============================================================
// EXPENSE TYPES
// ============================================================
export interface MonthlySpend {
  year: number;
  month: number; // 1-12
  total: number;
  byCategory: Record<string, number>;
  income: number;
  cashFlow: number;
  savingsRate: number;
}

export interface CategoryForecast {
  category: string;
  monthlyValues: number[];    // historical 6 months
  forecasts: number[];        // next 3 months predicted
  trend: 'increasing' | 'stable' | 'decreasing';
  regression: RegressionResult;
}

// ============================================================
// BUILD MONTHLY AGGREGATES from raw expenses
// ============================================================
export const buildMonthlyAggregates = (
  expenses: Array<{
    amount: number;
    category: string;
    date: Date;
    type?: 'expense' | 'income';
  }>
): MonthlySpend[] => {
  const map = new Map<string, MonthlySpend>();

  for (const exp of expenses) {
    const year  = exp.date.getFullYear();
    const month = exp.date.getMonth() + 1;
    const key   = `${year}-${month}`;

    if (!map.has(key)) {
      map.set(key, { year, month, total: 0, byCategory: {}, income: 0, cashFlow: 0, savingsRate: 0 });
    }

    const entry = map.get(key)!;

    if (exp.type === 'income') {
      entry.income += exp.amount;
    } else {
      entry.total += exp.amount;
      entry.byCategory[exp.category] = (entry.byCategory[exp.category] || 0) + exp.amount;
    }
  }

  // Calculate cash flow + savings rate
  for (const entry of map.values()) {
    entry.cashFlow    = entry.income - entry.total;
    entry.savingsRate = entry.income > 0 ? ((entry.income - entry.total) / entry.income) * 100 : 0;
  }

  return Array.from(map.values()).sort((a, b) =>
    a.year !== b.year ? a.year - b.year : a.month - b.month
  );
};

// ============================================================
// FORECAST PER CATEGORY
// ============================================================
export const forecastCategories = (
  monthlyAggregates: MonthlySpend[],
  forecastMonths = 3
): CategoryForecast[] => {
  // Get last 6 months
  const recent = monthlyAggregates.slice(-6);
  if (recent.length < 2) return [];

  // Collect all categories
  const allCategories = new Set<string>();
  recent.forEach(m => Object.keys(m.byCategory).forEach(c => allCategories.add(c)));

  return Array.from(allCategories).map(category => {
    const monthlyValues = recent.map(m => m.byCategory[category] || 0);
    const x = monthlyValues.map((_, i) => i + 1);
    const reg = linearRegression(x, monthlyValues);

    // Forecast next N months
    const nextBase = monthlyValues.length + 1;
    const forecasts = Array.from({ length: forecastMonths }, (_, i) =>
      predict(reg, nextBase + i)
    );

    // Trend: slope relative to mean monthly spend
    const mean = monthlyValues.reduce((a, b) => a + b, 0) / monthlyValues.length;
    const slopeRatio = mean > 0 ? reg.slope / mean : 0;
    const trend: CategoryForecast['trend'] =
      slopeRatio > 0.05 ? 'increasing' : slopeRatio < -0.05 ? 'decreasing' : 'stable';

    return { category, monthlyValues, forecasts, trend, regression: reg };
  });
};

// ============================================================
// BUDGET HEALTH SCORE (0-100)
// ============================================================
export interface BudgetHealth {
  score: number;
  grade: 'excellent' | 'good' | 'needs_attention' | 'critical';
  label: string;
  color: string;
}

export const calculateBudgetHealth = (
  monthlyBudget: number,
  spent: number,
  income: number,
  categoriesOverBudget: number
): BudgetHealth => {
  let score = 100;

  const spendingRate = monthlyBudget > 0 ? spent / monthlyBudget : 1;
  const savingsRate  = income > 0 ? (income - spent) / income : 0;
  const cashFlowNeg  = income > 0 && spent > income;

  if (spendingRate > 0.9)          score -= 30;
  else if (spendingRate > 0.75)    score -= 15;
  if (savingsRate < 0.1)           score -= 20;
  else if (savingsRate < 0.2)      score -= 10;
  if (categoriesOverBudget > 2)    score -= 15;
  else if (categoriesOverBudget > 0) score -= 7;
  if (cashFlowNeg)                 score -= 25;

  score = Math.max(0, Math.min(100, score));

  if (score >= 91) return { score, grade: 'excellent', label: 'Excellent',       color: '#4CAF50' };
  if (score >= 71) return { score, grade: 'good',      label: 'Good',            color: '#B8955A' };
  if (score >= 41) return { score, grade: 'needs_attention', label: 'Needs Attention', color: '#FF9800' };
  return              { score, grade: 'critical', label: 'Critical',        color: '#C47B6A' };
};

// ============================================================
// INCOME TYPE DETECTION from bank description
// ============================================================
export const detectIncomeType = (description: string): 'salary' | 'refund' | 'transfer' | 'interest' | 'other_income' => {
  const lower = description.toLowerCase();
  if (/salary|payroll|wages|pay run|employer|payslip/.test(lower)) return 'salary';
  if (/refund|return|credit back|cashback/.test(lower))             return 'refund';
  if (/transfer|tfr|bpay|internal/.test(lower))                     return 'transfer';
  if (/interest|int credit/.test(lower))                            return 'interest';
  return 'other_income';
};

// ============================================================
// FORMAT CURRENCY (AUD)
// ============================================================
export const formatAUD = (amount: number): string => {
  return amount.toLocaleString('en-AU', { style: 'currency', currency: 'AUD' });
};

export const formatCompact = (amount: number): string => {
  if (Math.abs(amount) >= 1000) {
    return `$${(amount / 1000).toFixed(1)}k`;
  }
  return formatAUD(amount);
};

